        ACCEPT_THIS_MISSION_YES_NO                                                    = 6750,  -- Accept this mission? Yes. No.
        YOU_HAVE_ACCEPTED_THE_MISSION                                                 = 6751,  -- You have accepted the mission.
        DEBUG_FLAG_RAISED_KUPO                                                        = 6752,  -- (DEBUG) Flag raised, kupo!
        WELCOME_MASTER_THIS_IS_YOUR_HOME_THE_MOG                                      = 6753,  -- Welcome, Master! This is your home, the Mog House, kupo!
        I_M_A_MOOGLE_WE_MOOGLES_LIKE_TAKING                                           = 6754,  -- I'm a moogle! We moogles like taking care of houses and items! Nice to meet you, kupo!
        I_LL_TELL_YOU_ALL_ABOUT_YOUR_MOG                                              = 6755,  -- I'll tell you all about your Mog House, kupo!
        FIRST_THE_BASICS_KUPO_OPEN_YOUR_MAIN_MENU                                     = 6756,  -- First, the basics, kupo! Open your main menu, Master. The button at the very bottom changes to Mog House when you're in your Mog House, kupo!
        PRESS_IT_AND_THE_MOG_HOUSE_MENU_WILL                                          = 6757,  -- Press it and the Mog House menu will appear! Everything you can do in your Mog House is there, kupo!
        THERE_ARE_LOTS_OF_THINGS_YOU_CAN_DO                                           = 6758,  -- There are lots of things you can do in your Mog House, kupo! It can be too much for some masters, kupo...
        SO_I_LL_TEACH_YOU_ABOUT_EACH_ONE                                              = 6759,  -- So I'll teach you about each one of them! Ask me what you want to know about, kupo!
        CHOOSE_THE_MOG_HOUSE_COMMAND_YOU_WANT_TO                                      = 6760,  -- Choose the Mog House command you want to know about, kupo!
        WHAT_DO_YOU_WANT_TO_KNOW_ABOUT_THE                                            = 6761,  -- What do you want to know about? The Mog Safe. Storage. The Delivery Box. Changing jobs. Gardening. Changing the layout. Mog House invitations. I got it, thanks, kupo!
        THE_MOG_SAFE_IS_WHERE_I_KEEP_ITEMS                                            = 6762,  -- The Mog Safe is where I keep items that you can't carry! It's an especially secure and solid safe, kupo!
        YOU_CAN_ONLY_PUT_SO_MANY_ITEMS_IN                                             = 6763,  -- You can only put so many items in it, kupo... But I'll guard them even if it means my life, kupo!
        THE_DELIVERY_BOX_IS_WHERE_YOU_CAN_SEND                                        = 6764,  -- The Delivery Box is where you can send letters to friends and receive items from various places, kupo!
        YOU_SHOULD_TAKE_THE_ITEMS_FROM_YOUR_DELIVERY                                  = 6765,  -- You should take the items from your Delivery Box and put them in your inventory when they arrive, kupo!
        IF_YOUR_DELIVERY_BOX_IS_FULL_NO_MORE                                          = 6766,  -- If your Delivery Box is full, no more deliveries can be made, and you can't send any mail either, kupo!
        YOU_CAN_SEND_ITEMS_AND_GIL_TO_YOUR                                            = 6767,  -- You can send items and gil to your friends with the Send command, kupo!
        SOMETIMES_IF_A_SPECIAL_FORCE_TAKES_HOLD_YOU                                   = 6768,  -- (Sometimes, if a special force takes hold, you can even deliver items with the "Exclusive" attribute, kupo...!)
        CHANGING_PEOPLE_S_JOBS_IS_A_SECRET_ABILITY                                    = 6769,  -- Changing people's jobs is a secret ability only we moogles can use, kupo!
        I_TAKE_OFF_ALL_YOUR_EQUIPMENT_AND_TAKE                                        = 6770,  -- I take off all your equipment and take you to a mysterious place, kupo!
        AND_THE_REST_IS_A_SECRET_KUPO                                                 = 6771,  -- And...the rest is a secret, kupo!
        ALL_MOOGLES_LIKE_TAKING_CARE_OF_PLANTS_KUPO                                   = 6772,  -- All moogles like taking care of plants, kupo!
        AS_LONG_AS_YOU_HAVE_A_FLOWERPOT_AND                                           = 6773,  -- As long as you have a flowerpot and seeds, I'll make it my personal responsibility to look after the plants you raise, kupo!
        THIS_MOG_HOUSE_IS_YOUR_VERY_OWN_ROOM                                          = 6774,  -- This Mog House is your very own room, kupo! But it's still a little bare, kupo...
        IT_NEEDS_SOME_FURNITURE_AND_MAYBE_SOME_PAINTINGS                              = 6775,  -- It needs some furniture and maybe some paintings to make it more cozy, kupo!
        IF_YOU_FIND_ANY_DURING_YOUR_TRAVELS_I                                         = 6776,  -- If you find any during your travels, I'll help you lay them out, kupo! I can't wait, kupo!
        STORAGE_SPACE_BECOMES_AVAILABLE_WHEN_YOU_PLACE_FURNITURE                      = 6777,  -- Storage space becomes available when you place furniture in your Mog House using the Layout command, kupo!
        IT_S_ALMOST_EXACTLY_THE_SAME_AS_USING                                         = 6778,  -- It's almost exactly the same as using your Mog Safe, kupo! Leave your items here for me to look after, kupo!
        YOU_CAN_INVITE_PARTY_AND_ALLIANCE_MEMBERS_INTO                                = 6779,  -- You can invite party and alliance members into your Mog House, kupo!
        YOU_CAN_SHOW_OFF_YOUR_EXPENSIVE_FURNITURE_HAVE                                = 6780,  -- You can show off your expensive furniture, have tea parties, plan your next great adventure--the possibilities are endless, kupo!
        ARE_YOU_SURE_KUPO_YOU_KNOW_EVERYTHING_ABOUT                                   = 6781,  -- Are you sure, kupo? You know everything about your Mog House, kupo?
        ARE_YOU_SURE_I_M_SURE_MAYBE_I                                                 = 6782,  -- Are you sure? I'm sure! Maybe I'm not so sure...
        AND_FINALLY_A_LITTLE_BIT_OF_ADVICE                                            = 6783,  -- And finally, a little bit of advice!
        IF_YOU_EVER_RUN_INTO_ANY_PROBLEMS_JUST                                        = 6784,  -- If you ever run into any problems, just ask your fellow adventurers for help!
        IF_YOU_TYPE_AE_HELLO_THEN_YOUR_MESSAGE                                        = 6785,  -- If you type /ae Hello!, then your message will be heard by many people.
        IF_YOU_TYPE_AE_FOLLOWED_BY_YOUR_ISSUE                                         = 6786,  -- If you type /ae followed by your issue or question, other adventurers will help you!
        REMEMBER_THAT_YOU_CAN_ONLY_DO_THIS_WHILE                                      = 6787,  -- Remember that you can only do this while in town, kupo!
        OKAY_KUPO_GOOD_LUCK_ON_YOUR_ADVENTURING_KUPO                                  = 6788,  -- Okay, kupo! Good luck on your adventuring, kupo!
        DO_YOU_WANT_ME_TO_TEACH_YOU_ABOUT                                             = 6789,  -- Do you want me to teach you about your Mog House again, kupo?
        ASK_ABOUT_YOUR_MOG_HOUSE_AGAIN_DON_T                                          = 6790,  -- Ask about your Mog House again? Don't ask. Ask.
        OVER_THE_MOUNTAINS_AND_THE_ROLLING_HILLS_I                                    = 6791,  -- Over the mountains and the rolling hills, I'll go wherever my master wills.t
        MASTER_I_TRAVELED_ALL_THE_WAY_HERE_AT                                         = 6792,  -- Master! I traveled all the way here at your bidding, kupo! Even a Rent-a-Room needs a moogle, kupo!
