        OH_MASTER_LOOK_AT_THIS_I_WAS_POKING                                           = 6846,  -- Oh, Master, look at this! I was poking around in the drawers of your %, when this % just popped out! I guess you never know what you're going to find until you look for it, kupo!
        ISN_T_THE_AROMA_POSITIVELY_SCRUMPTIOUS_IT_S                                   = 6847,  -- Isn't the aroma positively scrumptious? It's all yours, kupo! Consider it a present for being the magnificent master that you are!
