        I_THINK_THAT_YOU_ARE_READY_TO_ENTER                                           = 7276,  -- I think that you are ready to enter the leagues of the great chefs. Mix me up %.
        IF_IT_TICKLES_MY_TONGUE_I_LL_GRANT                                            = 7277,  -- If it tickles my tongue, I'll grant you the title of craftsman.
