        SORRY_TO_MAKE_AN_INNOCENT_PASSERBY_SUCH_AS                                    = 8094,  -- Sorry to make an innocent passerby such as yourself go to all that trouble for us...
        OUR_RHINOSTERY_IS_THE_MOST_UNUSUAL_OF_THE                                     = 8095,  -- Our Rhinostery is the most unusual of the five ministries, but we're a nice bunch once you get to know us. Do call by anytime, now.
