        MUST_HURRY                                                                    = 8101,  -- ...Must...hurry...
        LI_STEN_TO_RE_QUEST_AC_CEPT_RE                                                = 8102,  -- Li...sten...to...re...quest? Ac...cept... Re...fuse...
