        SOMETIMES_I_SPEND_ALL_NIGHT_TRYING_TO_HAVE                                    = 8107,  -- Sometimes I spend all night trying to have a decent conversation with Kenapa-Keppa.
        I_GUESS_UNLESS_YOU_HAVE_A_PERSONALITY_LIKE                                    = 8108,  -- I guess unless you have a personality like his, you wouldn't be able to spend years studying plants that don't talk.
        AS_FAR_AS_THE_STUDY_OF_PLANTS_HERE                                            = 8109,  -- As far as the study of plants here goes, Kenapa-Keppa is the one who most knows.
