        INCREDIBLE_KUPO_YOU_MUST_HAVE_NERVES_OF_DARKSTEEL                             = 10242,  -- Incredible, kupo! You must have nerves of darksteel! Here, you've earned this, kupo!
        YOU_TOOK_ANOTHER_DIVE_INTO_THE_DREADED_DUNGEON                                = 10243,  -- You took another dive into the dreaded dungeon, kupo? Well, you deserve a little something for your preternatural perseverance, kupo.
        YOU_HAVEN_T_EARNED_MY_REALLY_SPECIAL_PRESENT                                  = 10244,  -- You haven't earned my really special present yet! Only truly dauntless dungeon-delvers get that, kupo!
        THIS_ISN_T_ENOUGH_TO_PROVE_YOU_REACHED                                        = 10245,  -- This isn't enough to prove you reached the goal as a dungeon-delving duo. You have to bring me the item your partner received to show that you were both successful, kupo!
        TO_GO_ON_THIS_FRIGHT_FILLED_FACE_OFF                                          = 10246,  -- To go on this fright-filled face-off with fear, you need a partner who can prove you reached the goal. Come back when you have a buddy in bravery, kupo!
        THIS_ADVENTURE_INTO_ADVERSITY_IS_ONLY_AVAILABLE_TO                            = 10247,  -- This adventure into adversity is only available to two-person parties. Split up into pairs and talk to me again, kupo!
        PLEASE_COME_BACK_WITH_A_DIFFERENT_PARTNER_IT                                  = 10248,  -- Please come back with a different partner. It'll be no fun to scare you if your reactions are too similar, kupo!
        YOUR_PARTNER_ISN_T_READY_TO_GO_PLEASE                                         = 10249,  -- Your partner isn't ready to go. Please wait a little longer, kupo.
        YOUR_PARTNER_MUST_TALK_TO_ME_AS_WELL                                          = 10250,  -- Your partner must talk to me as well. I'll be waiting for you whenever you're ready, kupo.
        YOU_CAN_ONLY_CHOOSE_ONE_PARTNER_A_DAY                                         = 10251,  -- You can only choose one partner a day. Come back again tomorrow, kupo!
        HOLD_UP_THERE_IT_LOOKS_LIKE_YOUR_CANDIDATE                                    = 10252,  -- Hold up there! It looks like your candidate for courageous companionship has already got a partner! You can't choose that person at the moment, kupo!
        PLEASE_WAIT_A_LITTLE_LONGER_OR_FIND_A                                         = 10253,  -- Please wait a little longer or find a new partner before coming back, kupo.
        ARE_YOU_READY_TO_TEST_YOUR_COURAGE_KUPO                                       = 10254,  -- Are you ready to test your courage, kupo?
        ARE_YOU_READY_TO_GO_READY_KUPO_I                                              = 10255,  -- Are you ready to go? Ready, kupo! I'm too terrified, kupo!
        I_LL_BE_CHECKING_TO_SEE_IF_YOU                                                = 10256,  -- I'll be checking to see if you reached the goal. You can use this magical scroll to make a speedy return to town, kupo.
        IF_YOU_BOTH_SUCCEED_I_LL_HAVE_A                                               = 10257,  -- If you both succeed, I'll have a prize waiting for you! Now, off you go, kupo!
        YOU_CAN_ONLY_CARRY_ONE                                                        = 10258,  -- You can only carry one %.
        ARE_YOU_PARTICIPATING_IN_THIS_PETRIFYING_PILGRIMAGE_WITH                      = 10259,  -- Are you participating in this petrifying pilgrimage with the person in your present party?
        HEY_YOU_CHANGED_PARTNERS_YOU_CAN_T_SWITCH                                     = 10260,  -- Hey, you changed partners! You can't switch halfway through, kupo!
        WAIT_THE_NUMBER_OF_PEOPLE_IN_YOUR_PARTY                                       = 10261,  -- Wait, the number of people in your party has changed! You have to be in a two-person party, kupo!
        CHOOSE_YOUR_PARTNER_WISELY_COME_BACK_WHEN_YOU                                 = 10262,  -- Choose your partner wisely. Come back when you think you have a winning combo, kupo!
        BOO_HAH_HAH_KUPO                                                              = 10263,  -- Boo-hah-hah`...kupo!
        HUH_WHY_AREN_T_YOU_JUMPING_OUT_OF                                             = 10264,  -- Huh? Why aren't you jumping out of your skin in absolute terror? I would've died of fright, kupo!
        HERE_TAKE_THIS_AS_A_TESTAMENT_TO_YOUR                                         = 10265,  -- Here, take this as a testament to your courage. Exchange it for the item your partner received so you can prove that you both reached the goal safely, kupo!
        RETURN_WITH_THE_EVIDENCE_OF_YOUR_SUCCESS_TO                                   = 10266,  -- Return with the evidence of your success to the moogle in town. Handing over your partner's item will prove that you were both able to reach me, kupo!
        OH_AND_HERE_S_A_PICTURE_OF_HOW                                                = 10267,  -- Oh, and here's a picture of how your partner's face looked when I popped out of nowhere to scare you. You should hand this in at the same time, kupo! Kupupupu...
        THIS_PLACE_IS_CRAWLING_WITH_NASTIES_YOU_SHOULD                                = 10268,  -- This place is crawling with nasties. You should probably head back to town so you can testify to your partner's bravery.
        WHY_DO_GHOSTS_SAY_BOO_ANYWAY                                                  = 10269,  -- Why do ghosts say boo, anyway?
        I_HEARD_THAT_GOING_TO_A_DARK_SCARY                                            = 10270,  -- I heard that going to a dark, scary dungeon is the best way to test your courage. This place definitely qualifies, kupo!
        MAYBE_I_M_DOING_SOMETHING_WRONG_KUPO                                          = 10271,  -- Maybe I'm doing something wrong, kupo?
        IF_IT_GETS_OUT_THAT_I_HAVEN_T                                                 = 10272,  -- If it gets out that I haven't scared the wits out of a single person yet, I'm going to get into trouble, kupo...
        UNABLE_TO_ENTER_NEXT_AREA_EXPANSION_PACK_NOT                                  = 10273,  -- Unable to enter next area. Expansion pack not installed.
        THE_IRNC_HAS_DISPATCHED_ME_TO_HELP_SUPPORT                                    = 10274,  -- The IRNC has dispatched me to help support all those who wish to participate in Conflict.
        BEFORE_YOU_CAN_TAKE_PART_IN_THIS_CONFLICT                                     = 10275,  -- Before you can take part in this Conflict event, you must first possess %. You can obtain one from your nation's Conflict Commander, [Excenmille, stationed in Northern San d'Oria./Invincible Shield, stationed in the Metalworks in Bastok./Mhabi Molkot, stationed in Heavens Tower in Windurst.]
        ONLY_ADVENTURERS_WHO_HAVE_ACHIEVED_RANK_3_OR                                  = 10276,  -- Only adventurers who have achieved rank 3 or higher may take part in official Ballista matches. Please return when you have proven your loyalty to your home nation.
        HOWEVER_IF_YOU_STILL_WISH_TO_TAKE_PART                                        = 10277,  -- However, if you still wish to take part in Ballista, participation in matches held within Diorama Abdhaljs-Ghelsba is open to all citizens of Vana'diel.
        WHAT_SERVICES_DO_YOU_REQUIRE                                                  = 10278,  -- What services do you require?
        WHAT_CAN_I_HELP_YOU_WITH_NOTHING_THE                                          = 10279,  -- What can I help you with? Nothing. The upcoming Ballista matches. The Ballista schedule. A teleport to the Ballista match. The rules of Ballista. Borrow/Return %. Borrow/Return %. Borrow/Return %. The upcoming Brenner matches. A teleport to the Brenner match (Lv #). The rules of Brenner. Borrow/Return %. Borrow/Return %.
        I_AM_ALLOWED_TO_TELEPORT_BALLISTA_PARTICIPANTS_TO                             = 10280,  -- I am allowed to teleport Ballista participants to the site of the next match in exchange for % or # Ballista [Point/Points]. This service is available from twenty-four hours before the start of the match, up until the end of the match.
        CAN_BE_RECEIVED_AFTER_PARTICIPATING_IN_BALLISTA_OR                            = 10281,  -- % can be received after participating in Ballista, or in the event one is not able to participate due to an influx (or lack) of entries.
        I_M_SORRY_BUT_I_AM_NOT_AUTHORIZED                                             = 10282,  -- I'm sorry, but I am not authorized to teleport persons who do not meet the level requirement for the match.
        THE_FOLLOWING_INFORMATION_REGARDS_THE_MATCH_I_AM                              = 10283,  -- The following information regards the match I am currently authorized to teleport you to...
        TELEPORT_RIGHT_AWAY_NOT_YET                                                   = 10284,  -- Teleport? Right away. Not yet.
        I_AM_SORRY_BUT_I_CANNOT_TELEPORT_YOU                                          = 10285,  -- I am sorry, but I cannot teleport you at this time.
        I_AM_SORRY_BUT_I_CANNOT_TELEPORT_YOU_2                                        = 10286,  -- I am sorry, but I cannot teleport you at this time. Please return when there are less than twenty-four hours remaining until the next match.
        CURRENTLY_THE_FOLLOWING_SPECIAL_RULES_ARE_BEING_IMPLEMENTED                   = 10287,  -- Currently, the following special rules are being implemented...
        CURRENTLY_THERE_ARE_NO_SPECIAL_RULES_BEING_IMPLEMENTED                        = 10288,  -- Currently, there are no special rules being implemented.
        THE_NEXT_SCHEDULED_BALLISTA_MATCH_IS_AREA_MATCHUP                             = 10289,  -- The next scheduled Ballista match is: Area: [Jugner Forest/Pashhow Marshlands/Meriphataud Mountains] Matchup: [San d'Oria vs Bastok/Bastok vs Windurst/Windurst vs San d'Oria] Level Restriction: [None/@/@/30/40/50/60/] Participation Fee: # gil Match Format: [All or Nothing * Normal Items Allowed/All or Nothing * Normal Items Restricted/Best of Three * Normal Items Allowed]
        ENTRIES_ARE_NOW_BEING_ACCEPTED                                                = 10290,  -- Entries are now being accepted.
        ENTRY_PERIOD_BEGINS_VANA_DIEL_EARTH                                           = 10291,  -- Entry period begins: Vana'diel: Earth:
        MATCH_BEGINS_VANA_DIEL_EARTH                                                  = 10292,  -- Match begins: Vana'diel: Earth:
        WHILE_WEARING_DURING_A_MATCH_YOU_WILL_BE                                      = 10293,  -- While wearing % during a match, you will be able to hear the orders of your nation's Pursuivant. His advice will aid you in battle.
        ALSO_YOU_WILL_BE_INFORMED_OF_ALL_THE                                          = 10294,  -- Also, you will be informed of all the latest match information when entering select cities.
        WOULD_YOU_LIKE_YES_NO                                                         = 10295,  -- Would you like %? Yes. No.
        RETURN_YOUR_YES_NO                                                            = 10296,  -- Return your %? Yes. No.
        OBTAINED_3                                                                    = 10297,  -- Obtained: %.
        BY_CARRYING_WITH_YOU_DURING_A_BALLISTA_MATCH                                  = 10298,  -- By carrying % with you during a Ballista match, any temporary item you quarry will be automatically placed in your bag without you having to select whether you wish to keep it, use it, or throw it away.
        WHEN_YOUR_INVENTORY_IS_FULL_OR_YOU_CANNOT                                     = 10299,  -- When your inventory is full, or you cannot carry any more of a certain item, the newly quarried item will be automatically discarded. If you wish, I can lend you one of these shovels, free of charge.
        BORROW_YES_NO                                                                 = 10300,  -- Borrow %? Yes. No.
        YOU_BORROW                                                                    = 10301,  -- You borrow %!
        RETURN_THE_YES_NO                                                             = 10302,  -- Return the %? Yes. No.
        YOU_RETURN_THE                                                                = 10303,  -- You return the %!
        WHEN_CARRYING_WITH_YOU_WHILE_PARTICIPATING_IN_A                               = 10304,  -- When carrying % with you while participating in a Ballista match, you will have the option to keep or throw away the first Petra you find. This is useful when you want to continue /sprinting.
        IF_YOU_WISH_I_CAN_LOAN_YOU_ONE                                                = 10305,  -- If you wish, I can loan you one, free of charge.
        BORROW_YES_NO_2                                                               = 10306,  -- Borrow %? Yes. No.
        RETURN_THE_YES_NO_2                                                           = 10307,  -- Return the %? Yes. No.
        WHEN_IN_POSSESSION_OF_THE_KEY_ITEM_TEMPORARY                                  = 10308,  -- When in possession of the key item %, temporary items will be automatically added to the player's inventory when quarried.
        WHEN_A_PLAYER_S_INVENTORY_EXCEEDS_THE_MAXIMUM                                 = 10309,  -- When a player's inventory exceeds the maximum capacity, any temporary item found will simply be discarded. You can speak to me to borrow or return the shovel at any time.
        BORROW_THE_YES_NO                                                             = 10310,  -- Borrow the %? Yes. No.
        RETURN_THE_YES_NO_3                                                           = 10311,  -- Return the %? Yes. No.
        WHEN_IN_POSSESSION_OF_THE_KEY_ITEM_YOU                                        = 10312,  -- When in possession of the key item %, you will have the choice of keeping or throwing away the first Petra you quarry. You will also retain the ability to sprint.
        YOU_CAN_SPEAK_TO_ME_TO_BORROW_OR                                              = 10313,  -- You can speak to me to borrow or return the band at any time.
        SELECT_A_MATCH_LEVEL_VIEW_ALL_LEVELS_NO                                       = 10314,  -- Select a match level... View all levels. No restriction (# gil per match). Level 60 (# gil per match). Level 50 (# gil per match). Level 40 (# gil per match). Level 30 (# gil per match). Return.
        SELECT_FOR_MORE_INFORMATION_NEXT_RETURN                                       = 10315,  -- Select for more information... , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. % / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] , [ / / /Lv. 30/Lv. 40/Lv. 50/Lv. 60/Lv. ] Next. Return.
        MATCH_ENTRY_PERIOD_BEGINS_BRIEFING_BEGINS                                     = 10316,  -- <Match #> Entry period begins: Briefing begins:
        I_APOLOGIZE_BUT_YOUR_LEVEL_IS_TOO_LOW                                         = 10317,  -- I apologize, but your level is too low to participate in an official Brenner match.
        OFFICIAL_MATCHES_ARE_SCHEDULED_TO_BEGIN_AT_THE                                = 10318,  -- Official matches are scheduled to begin at the following times: Match 1: Match 2: Match 3:
        TELEPORTATION_TO_THE_ISLE_IS_FREE_OF_CHARGE                                   = 10319,  -- Teleportation to the Isle is free of charge, but a participation fee of # gil is required before each match.
        TRAVEL_TO_THE_ISLE_YES_NOT_YET                                                = 10320,  -- Travel to the Isle? Yes. Not yet.
        WHAT_WOULD_YOU_LIKE_TO_KNOW_ABOUT_BASIC                                       = 10321,  -- What would you like to know about? Basic rules. Official/private matches. Flammen-Brenner. Flamme. Match score. Petras and quarrying. Sprint. KO. Return.
        THE_BASIC_RULES_OF_BRENNER_ARE_AS_FOLLOWS                                     = 10322,  -- The basic rules of Brenner are as follows:
        FIRST_THE_PARTICIPANTS_DIVIDE_INTO_TWO_TEAMS_EACH                             = 10323,  -- First, the participants divide into two teams. Each side's camp contains the same number of Flammen-Brenner.
        AT_THE_BEGINNING_OF_THE_MATCH_HALF_OF                                         = 10324,  -- At the beginning of the match, half of each side's Flammen-Brenner will be ablaze with Flamme, or flame, while the other half will remain unlit.
        PARTICIPANTS_CAN_SEIZE_A_FLAMME_FROM_THE_OPPOSING                             = 10325,  -- Participants can seize a Flamme from the opposing side's Flammen-Brenner and carry it around the Isle.
        THE_GOAL_IS_TO_STEAL_YOUR_OPPONENT_S                                          = 10326,  -- The goal is to steal your opponent's Flamme and use them to light your side's Flammen-Brenner.
        THE_SIDE_THAT_SUCCEEDS_IN_LIGHTING_ALL_OF                                     = 10327,  -- The side that succeeds in lighting all of its Flammen-Brenner will be declared the winner after a specified amount of time.
        IF_NEITHER_SIDE_IS_VICTORIOUS_BEFORE_THE_MATCH                                = 10328,  -- If neither side is victorious before the match ends, the outcome will be judged based on the score. The match score section of the rulebook contains more information on this subject.
        BRENNER_IS_SIGNIFICANTLY_DIVIDED_INTO_PUBLIC_AND_PRIVATE                      = 10329,  -- Brenner is significantly divided into public and private matches. Official matches are held periodically according to level and feature general participation.
        YOU_CANNOT_RESERVE_THE_ISLE_WHEN_AN_OFFICIAL                                  = 10330,  -- You cannot reserve the Isle when an official match is being held.
        NO_ITEMS_ARE_NECESSARY_FOR_PARTICIPATION_BUT_A                                = 10331,  -- No items are necessary for participation, but a minor fee will be collected. You will be unable to participate if your level is too low.
        THE_MATCH_OUTCOME_WILL_BE_RECORDED_UNLESS_THE                                 = 10332,  -- The match outcome will be recorded unless the number of participants fails to exceed # members, or if there are fewer than # members in a match where the two sides' numbers differ. In such cases, the game will be considered a training match and will not be recorded.
        PRIVATE_MATCHES_REQUIRE_A_RESERVATION_AND_PARTICIPATION_MAY                   = 10333,  -- Private matches require a reservation, and participation may be limited. The Master of Ceremonies (MC) can freely adjust the rules and control match proceedings.
        LS_LIGA_IS_A_FORM_OF_PRIVATE_MATCH                                            = 10334,  -- LS Liga is a form of private match. You can learn more about LS Liga by speaking to a Marshal.
        A_FLAMMEN_BRENNER_IS_A_DEVICE_THAT_CONTAINS                                   = 10335,  -- A Flammen-Brenner is a device that contains a Flamme (flame). The Flammen-Brenner is covered by a grate that will open after taking a set amount of damage, exposing the Flamme.
        THE_PARTICIPANTS_MUST_UTILIZE_THIS_CHANCE_TO_SEIZE                            = 10336,  -- The participants must utilize this chance to seize the Flamme before the grate recloses. Once the grate is closed, the Flammen-Brenner will begin recovering from the damage it has been dealt.
        IF_YOU_MANAGE_TO_OPEN_THE_OPPOSING_TEAM                                       = 10337,  -- If you manage to open the opposing team's Flammen-Brenner and capture their Flamme, you should make haste to light one of the Flammen-Brenner on your side.
        AFTER_A_CERTAIN_AMOUNT_OF_TIME_THE_FLAMME                                     = 10338,  -- After a certain amount of time, the Flamme will burn out and the opposing team's Flammen-Brenner will be relit.
        ALSO_PLEASE_NOTE_THAT_YOU_CANNOT_QUICKEN_YOUR                                 = 10339,  -- Also, please note that you cannot quicken your pace using any special abilities while you are in possession of a Flamme.
        IN_THE_EVENT_THAT_NEITHER_SIDE_FULFILLS_THE                                   = 10340,  -- In the event that neither side fulfills the conditions for victory, the outcome of the match will be evaluated based on score.
        TEN_POINTS_ARE_AWARDED_TO_EACH_SIDE_FOR                                       = 10341,  -- Ten points are awarded to each side for every lit Flammen-Brenner, while one point is awarded whenever a Flamme is captured, used to light a Flammen-Brenner, or recaptured from an opponent. One point is also awarded for protecting the Flammen-Brenner for a certain period of time.
        LIKE_BALLISTA_QUARRY_QUARRY_CAN_BE_USED_WHILE                                 = 10342,  -- Like Ballista, quarry (/quarry) can be used while playing Brenner. Participants may use this ability to dig up Petras and temporary items.
        HOWEVER_UNLIKE_BALLISTA_PETRAS_BRENNER_PETRAS_HAVE_NO                         = 10343,  -- However, unlike Ballista Petras, Brenner Petras have no effect on the match score. You can trade a Petra to a Pursuivant to recover your HP and MP at no expense to TP.
        SPRINT_CANNOT_BE_USED_WHILE_CARRYING_A_PETRA                                  = 10344,  -- Sprint cannot be used while carrying a Petra. Also, please note that the scout ability cannot be used in Brenner.
        PETRAS_WILL_BE_LOST_IN_THE_EVENT_OF                                           = 10345,  -- Petras will be lost in the event of a KO, but can be carried over from one match to another.
        THE_SPRINT_SPRINT_ABILITY_CAN_BE_USED_TO                                      = 10346,  -- The sprint (/sprint) ability can be used to increase the player's speed when not in possession of a Flamme or Petras.
        IN_THE_EVENT_OF_A_KO_YOU_WILL                                                 = 10347,  -- In the event of a KO, you will be returned to your team's camp. However, recovery will take longer the more often you fall in battle.
        IN_OTHER_WORDS_YOU_WILL_RECEIVE_A_PENALTY                                     = 10348,  -- In other words, you will receive a penalty if you fall immediately after recovering from KO. In addition, your TP will be reduced to zero and you will lose any Petras in your possession.
        I_M_SORRY_I_WASN_T_LISTENING_COULD                                            = 10349,  -- I'm sorry. I wasn't listening. Could you start over from the beginning?
        WHAT_DO_YOU_WISH_TO_KNOW_ABOUT_BASIC                                          = 10350,  -- What do you wish to know about? Basic rules. About the Petra. About Sprint. About Scout. About Gate Breach. About area-specific rules. About returning to battle. About special rules. Nothing at the moment.
        BALLISTA_IS_AN_EXERCISE_ONCE_USED_BY_THE                                      = 10351,  -- Ballista is an exercise once used by the San d'Orian armies to train the Royal Knights in the art of the siege. The word ballista means to throw a stone, and the game has been a part of Vana'dielian military history for centuries.
        THE_RULES_ARE_SIMPLE_BALLISTA_IS_PLAYED_BY                                    = 10352,  -- The rules are simple. Ballista is played by two teams over a number of hours (Vana'diel time). The team with the most points at the end of the match is the victor.
        PLAYERS_FROM_BOTH_TEAMS_MUST_SEARCH_FOR_PETRAS                                = 10353,  -- Players from both teams must search for Petras that a Herald has buried in various locations across the battlefield. The players must then take these stones and throw them into targets known as Rooks.
        THESE_ROOKS_CAN_APPEAR_IN_VARIOUS_LOCATIONS_AROUND                            = 10354,  -- These Rooks can appear in various locations around the battlefield, and both teams are allowed to throw their Petras into them.
        FINALLY_A_PLAYER_S_STRENGTH_IS_ADJUSTED_DEPENDING                             = 10355,  -- Finally, a player's strength is adjusted depending on his or her level. It is felt that this ultimately allows for a more balanced battle.
        PETRAS_CAN_BE_BURIED_ANYWHERE_ONCE_A_PLAYER                                   = 10356,  -- Petras can be buried anywhere. Once a player believes he or she has found one, the Quarry (/quarry) command should be used to dig up the area at his or her feet.
        SOMETIMES_A_PLAYER_MAY_FIND_ITEMS_OTHER_THAN                                  = 10357,  -- Sometimes a player may find items other than Petras, such as potions. These temporary items can only be used during the current match (or Best of Three series).
        PLAYERS_CAN_CARRY_MORE_THAN_ONE_PETRA_BUT                                     = 10358,  -- Players can carry more than one Petra, but they cannot throw the stones away once they have obtained them. However, players will lose their Petras if they: (1) Successfully throw them into a rook. (2) Leave the area. (3) Are knocked out.
        BUT_DON_T_FORGET_A_PLAYER_WILL_BE                                             = 10359,  -- But don't forget, a player will be unable to use the Sprint command while in possession of a Petra. And, players can only use the Scout command if they carry one of the stones.
        AS_ONE_CAN_SEE_CAREFUL_PLANNING_AND_IMPECCABLE                                = 10360,  -- As one can see, careful planning and impeccable timing are the keys to victory.
        ALL_PARTICIPANTS_OF_BALLISTA_WILL_HAVE_THE_ABILITY                            = 10361,  -- All participants of Ballista will have the ability to use the Sprint command. This will temporarily increase one's movement speed, creating a better chance to find and obtain Petras.
        HOWEVER_REMEMBER_THAT_ONCE_A_PLAYER_HAS_OBTAINED                              = 10362,  -- However, remember that once a player has obtained a Petra, he or she will be unable to use the Sprint command. In its place, though, one may use the Scout command.
        THE_LOCATIONS_OF_THE_ROOKS_ARE_CONSTANTLY_CHANGING                            = 10363,  -- The locations of the Rooks are constantly changing. This makes it quite difficult to find the targets by just randomly walking about the area.
        COMMUNICATION_WITH_ONE_S_TEAM_MEMBERS_IS_OF                                   = 10364,  -- Communication with one's team members is, of course, one way to locate Rooks. However, another way is by using the Scout command. This will inform a player of the approximate location of the nearest Rook.
        FINALLY_SCOUT_CAN_ONLY_BE_USED_WHEN_A                                         = 10365,  -- Finally, Scout can only be used when a player is carrying a Petra. Because Sprint cannot be used at this time, players must be weary of approaching enemies.
        SO_A_PETRA_HAS_BEEN_OBTAINED_AND_A                                            = 10366,  -- So, a Petra has been obtained and a Rook located. Now all that's left is tossing the stone in, right? Wrong.
        THERE_IS_ONE_ASPECT_OF_BALLISTA_THAT_HAS                                      = 10367,  -- There is one aspect of Ballista that has yet to be mentioned...and this is where the real battle begins.
        TO_THROW_A_PETRA_INTO_A_ROOK_A                                                = 10368,  -- To throw a Petra into a Rook, a player must first wait until the Rook's gate is open. This takes impeccable timing, as the gate is only open for a short while.
        BUT_NOT_JUST_ANYONE_CAN_SCORE_POINTS_THIS                                     = 10369,  -- But not just anyone can score points this way. A player must first take down a member of the opposing team and achieve Gate Breach status. Only then will his or her shots count.
        THIS_EXTREME_METHOD_OF_COMBAT_IS_WHAT_MADE                                    = 10370,  -- This extreme method of combat is what made the ancient game of Ballista famous, and transformed its participants into heroes.
        RUNNING_ABOUT_LOOKING_FOR_STONES_IS_NO_DIFFERENT                              = 10371,  -- Running about looking for stones is no different from a child's game of hide-and-seek. Knowing when to strike is what separates the men from the boys.
        THE_FOLLOWING_MATCH_TYPES_ARE_AREA_SPECIFIC_ALL                               = 10372,  -- The following match types are area-specific: All or Nothing (one match) * Normal Items Allowed: Jugner Forest All or Nothing (one match) * Normal Items Restricted: Pashhow Marshlands Best of Three (three matches) * Normal Items Allowed: Meriphataud Mountains
        BEST_OF_THREE_SERIES_RULES_ARE_AS_FOLLOWS                                     = 10373,  -- Best of Three series rules are as follows: Winning a match will earn a nation one match point. The nation with the most match points at the end of the series will be declared the victor. Winning the third and final match and producing the high scorer will result in two match points awarded. This allows both sides the chance for come-from-behind victories.
        BETWEEN_EACH_OF_THE_MATCHES_A_SHORT_INTERVAL                                  = 10374,  -- Between each of the matches, a short interval will be implemented. During this interval, Invisible and Sneak will be cast on all participants. We suggest this time be used to discuss strategies with the other members of your nation's forces.
        PLAYERS_WILL_BE_FORBIDDEN_FROM_USING_ANY_ITEMS                                = 10375,  -- Players will be forbidden from using any items they bring to the battlefield. Only temporary items that are quarried may be used. A total of fifteen temporary items (though only one of each type) can be carried.
        WHEN_THIS_RULE_IS_IN_EFFECT_ALL_PLAYERS                                       = 10376,  -- When this rule is in effect, all players will be presented with five complimentary temporary items at the beginning of the match.
        FOR_MORE_INFORMATION_ON_TEMPORARY_ITEMS_REFER_TO                              = 10377,  -- For more information on temporary items, refer to the special rules.
        AFTER_BEING_KO_D_IF_A_PLAYER_CHOOSES                                          = 10378,  -- After being KO'd, if a player chooses to be revived at the spot he was defeated, 100% of all HP and 50% of all MP will be restored. In addition, the player will maintain 50% of the TP he had earned.
        IF_A_PLAYER_CHOOSES_TO_RETURN_TO_THEIR                                        = 10379,  -- If a player chooses to return to their force's camp, HP and MP will be fully restored, but all TP will be lost.
        PLEASE_NOTE_THAT_MANY_OF_THE_RULES_PREVIOUSLY                                 = 10380,  -- Please note that many of the rules previously considered special have been fully implemented. Also, several new special rules have been added.
        LEARN_ABOUT_WHICH_SPECIAL_RULES_TEMPORARY_ITEMS_BALLISTA                      = 10381,  -- Learn about which special rules? Temporary items. Ballista Points. Scoring restrictions. Gate Breach radius expansion. Resistance to Sleep. Open entries. Minimum level restrictions. Re-entry restrictions. Participant & Rook numbers. Experience Points. Return.
        PREVIOUSLY_PARTICIPANTS_IN_BALLISTA_WERE_REQUIRED_TO_USE                      = 10382,  -- Previously, participants in Ballista were required to use an item the moment they dug it up using the /quarry command. However, players can now stock these items as temporary items for use at any time during the match.
        PLAYERS_CAN_HOLD_UP_TO_TEN_TEMPORARY_ITEMS                                    = 10383,  -- Players can hold up to ten temporary items, but only one of each type. If a player finds an item that they already possess, they must use it immediately or throw it away.
        IF_PLAYERS_WHO_POSSESS_TEN_TEMPORARY_ITEMS_FIND                               = 10384,  -- If players who possess ten temporary items find an item that they have not already obtained, they will also have the option to exchange it with one of their current items.
        ALSO_PLAYERS_WILL_NOT_AT_ANY_TIME_BE                                          = 10385,  -- Also, players will not, at any time, be allowed to trade temporary items. However, there are items that can be used on other Ballista participants. Please note that players may not be able to use these special items as soon as they are quarried.
        FINALLY_THE_HERALDS_WILL_COLLECT_TEMPORARY_ITEMS_WHEN                         = 10386,  -- Finally, the Heralds will collect temporary items when the match (the third in a Best of Three series) has concluded.
        BALLISTA_POINTS_ARE_REWARDED_TO_EACH_COMPETITOR_BASED                         = 10387,  -- Ballista Points are rewarded to each competitor based on his or her performance in a single Ballista match. The maximum number of points that can be accumulated per match is #.
        WHILE_IT_IS_TAKEN_INTO_CONSIDERATION_SCORING_PETRAS                           = 10388,  -- While it is taken into consideration, scoring Petras is not the only way to earn Ballista Points. Assisting allies and defeating members of the enemy forces can also earn a high score.
        BALLISTA_POINTS_CAN_BE_TRADED_FOR_SPECIAL_VOUCHERS                            = 10389,  -- Ballista Points can be traded for special vouchers, which may be exchanged for free temporary items at the start of new matches.
        HOWEVER_REMEMBER_THAT_DEPENDING_ON_THE_LEVEL_RESTRICTION                      = 10390,  -- However, remember that depending on the level restriction of the match, certain vouchers will not be redeemed at the beginning of a match. Speak with a Marshal directly after a match to register your points.
        PLAYERS_WILL_ONLY_BE_ALLOWED_TO_SCORE_UP                                      = 10391,  -- Players will only be allowed to score up to five Petras at a time. Also, a player's Gate Breach status will be automatically disengaged if a Petra is not scored within a certain amount of time. The amount of time is increased for those members of the team currently behind in points.
        ALL_ALLIES_WITHIN_A_CERTAIN_RADIUS_WILL_ACHIEVE                               = 10392,  -- All allies within a certain radius will achieve Gate Breach status when a member of the enemy forces is defeated.
        PLAYERS_RESISTANCE_TO_SLEEP_WILL_BE_INCREASED                                 = 10393,  -- Players' resistance to sleep will be increased.
        DURING_THE_ENTRY_PERIOD_FROM_ALL_ADVENTURERS_WILL                             = 10394,  -- During the entry period, from #:, all adventurers will be allowed to join the forces with the smallest number of participants, regardless of allegiance. Open entries will be accepted until both sides have reached maximum capacity.
        IN_ORDER_TO_ENSURE_BALANCED_MATCHES_THE_FOLLOWING                             = 10395,  -- In order to ensure balanced matches, the following level limits are enforced: Level 30 matches: 1`30
        LEVEL_40_MATCHES_31_40_LEVEL_50_MATCHES                                       = 10396,  -- Level 40 matches: 31`40 Level 50 matches: 41`50 Level 60 matches: 51`60 Unrestricted matches: 61`
        PLEASE_NOTE_THAT_ANY_PARTICIPANT_WHO_CANCELS_HIS                              = 10397,  -- Please note that any participant who cancels his or her registration will not be allowed to re-apply for the same match.
        WHEN_THE_TOTAL_NUMBER_OF_PARTICIPANTS_IN_A                                    = 10398,  -- When the total number of participants in a match is less than 40, the location of the two camps will be adjusted. Also in this case, the number of Rooks will be reduced to two.
        ANY_ADVENTURER_WHOSE_MAIN_LEVEL_IS_OVER_30                                    = 10399,  -- Any adventurer whose main level is over 30 will receive EXP for participating in a Ballista match. However, no EXP will be rewarded if the adventurer fails to actively take part in the match.
        READ_WHICH_CHAPTER_ON_B_P_RANKING_BASIC                                       = 10400,  -- Read which chapter on B.P. Ranking? Basic Information. Registering Points. Rewards. Chevron & Title List. None.
        BALLISTA_POINT_RANKING_IS_BASED_UPON_ALL_BALLISTA                             = 10401,  -- Ballista Point Ranking is based upon all Ballista Points registered from the past ten matches in each of the three participating battle areas.
        ANYONE_WHO_WISHES_TO_TAKE_PART_IN_THE                                         = 10402,  -- Anyone who wishes to take part in the ranking needs to register his/her] points within four hours (Vana'diel time) from the end of the previous match.
        AFTER_THE_REGISTRATION_PERIOD_ENDS_PLAYERS_CAN_COMPARE                        = 10403,  -- After the registration period ends, players can compare their record with those of the previous nine matches.
        IF_AT_ANY_TIME_A_PLAYER_RANKS_IN                                              = 10404,  -- If, at any time, a player ranks in the top ten (overall) or first for a specific job, he/she] will have the opportunity to receive a special chevron as well as a new title.
        THERE_ARE_FOUR_TYPES_OF_CHEVRONS_AND_TITLES                                   = 10405,  -- There are four types of chevrons and titles awarded to top-ten players (gold/mythril/silver/bronze), as well as twenty-two different types awarded for outstanding performances by players of each of the twenty-two jobs.
        WEARING_A_CHEVRON_DURING_A_BALLISTA_MATCH_WILL                                = 10406,  -- Wearing a chevron during a Ballista match will automatically change a player's current title. If a player wishes to possess this title after a match as well, he/she] must contact a certain bard in San d'Oria.
        ALSO_WHILE_WEARING_A_CHEVRON_PLAYERS_WILL_BE                                  = 10407,  -- Also, while wearing a chevron, players will be able to trade Ballista Points for temporary items not available to all players.
        HOWEVER_THE_RULES_OF_BALLISTA_STATE_THAT_PLAYERS                              = 10408,  -- However, the rules of Ballista state that players may only possess a certain chevron for no longer than one half Vana'diel year. When that time comes, they are required to return the chevron before being allowed to participate in any further matches.
        FINALLY_CHECKING_SOMEONE_DURING_A_BALLISTA_MATCH_WILL                         = 10409,  -- Finally, checking someone during a Ballista match will display the total number of chevrons that person has accumulated to date.
        VIEW_WHICH_CHEVRON_TITLE_1ST_OVERALL_2ND_OVERALL                              = 10410,  -- View which chevron/title? 1st (overall). 2nd (overall). 3rd (overall). 4th-10th (overall). 1st (warrior). 1st (monk). 1st (white mage). 1st (black mage). 1st (red mage). 1st (thief). 1st (paladin). 1st (dark knight). 1st (beastmaster). 1st (bard). 1st (ranger). 1st (samurai). 1st (ninja). 1st (dragoon). 1st (summoner). 1st (blue mage). 1st (corsair). 1st (puppetmaster). 1st (dancer). 1st (scholar). 1st (geomancer). 1st (rune fencer). Return.
