        MUNCH_MUNCH_CHEW_CHEW_WHAT_S_THAT_YOU_4                                       = 10481,  -- Munch-munch...chew-chew... What's that? You have a question you want to ask me, the man on the spot?
        YOU_WANNA_KNOW_IF_THREE_TARUTARU_WEARING_STRANGE                              = 10482,  -- You wanna know if three Tarutaru wearing strange clothing were here while I was stewing over my stew?
        I_DID_SEE_THREE_TARUTARU_WITH_APPETITES_ALMOST                                = 10483,  -- I did see three Tarutaru with appetites almost as big as mine, if that helps. Munch-munch...chew-chew...slurp...
