        THIS_IS_ALL_YOUR_FAULT_YOU_NONSENSE_SPOUTING                                  = 10512,  -- This is all your fault, you nonsense-spouting troublemakers! What annoying pit did you crawl out of!?
        WE_RE_FROM_TAVNAZIA                                                           = 10513,  -- We're from Tavnazia!
        WE_WERE_BLOWN_THROUGH_THE_AIR_OVER_THE                                        = 10514,  -- We were blown through the air, over the seas and mountains!
