        TAVNAZIA_THAT_FORMER_CITY_NOW_BIG_HOLE_IN                                     = 10516,  -- Tavnazia? That former city, now big hole in the ground, Tavnazia? I mean, I used to travel there quite often on business before it was destroyed...
        MUNCH_MUNCH_CHEW_CHEW_YOU_ADMIT_IT_YOU                                        = 10517,  -- Munch-munch...chew-chew... You admit it! You've been to Tavnazia!
        THEN_THESE_THREE_REALLY_ARE_YOUR_CHILDREN                                     = 10518,  -- Then these three really are your children...
