        NOW_IT_S_ONLY_A_MATTER_OF_TIME                                                = 10752,  -- Now it's only a matter of time before those stinking beastmen find all the cards and we moogles lose the game, kupo!
        AND_THAT_S_WHY_WE_NEED_YOUR_HELP                                              = 10753,  -- And that's why we need your help, kupo! Would you go out into the field and find the cards before the Goblins do?
        THERE_IS_A_VARIETY_OF_DIFFERENT_SETS_FOR                                      = 10754,  -- There is a variety of different sets. For each set you bring back safely, I'll secretly give you the present that we were going to give the Goblins, kupo!
        FOR_STARTERS_WHY_DON_T_YOU_TRY_FINDING                                        = 10755,  -- For starters, why don't you try finding %, %, and %? That should throw those smelly Gobs for a real spin, kupo!
        GREAT_A_WHOLE_SET_KUPO_AH_I_WISH                                              = 10756,  -- Great! A whole set, kupo! Ah, I wish I could be there to see the look on those Gobs' faces when all they find is an empty hole. Oh, right! Here's your reward, kupo!
