        WOW_ANOTHER_SET_YOU_DON_T_KNOW_HOW                                            = 10758,  -- Wow! Another set! You don't know how much this means to us, kupo! Here, take this!
        HAVE_YOU_SEEN_THE_DECORATIONS_THE_DOLL_FESTIVAL                               = 10759,  -- Have you seen the decorations? The Doll Festival has started, kupo!
