        I_CAN_SEE_THE_AURA_YOU_VE_ABSORBED                                            = 10794,  -- I can see the aura you've absorbed from the enemy! Here's your reward, kupo!
        WITH_ALL_THE_AURA_YOU_VE_ABSORBED_WITH                                        = 10795,  -- With all the aura you've absorbed with the %, we've managed to create a new weapon. We'd like you to have it, kupo!
        FESTIVAL_TIME_KUPO_WE_MOOGLES_HAVE_COME_UP                                    = 10796,  -- Festival time, kupo`!!! We moogles have come up with a new game for you to enjoy called "Azimuth Circle"!
        AZIMUTH_CIRCLE_IS_PLAYED_IN_PAIRS_FIRST_FIND                                  = 10797,  -- Azimuth Circle is played in pairs! First, find a partner and make a party, kupo!
