        AT_EACH_LOCATION_LIES_A_COMPASS_THAT_POINTS                                   = 10800,  -- At each location lies a compass that points in the direction of your partner's special checkpoint! The directions will be indicated from the viewpoint of your partner, kupo`.
        FIND_BOTH_OF_YOUR_SPECIAL_CHECKPOINTS_AND_EXCHANGE                            = 10801,  -- Find both of your special checkpoints and exchange the items you receive from them! Bring those items to us. We will give you a reward in exchange, kupo!
        THAT_S_ALL_THERE_IS_TO_IT_KUPO                                                = 10802,  -- That's all there is to it, kupo! To participate, make a party of two and talk to a moogle!
        THAT_S_ALL_THERE_IS_TO_IT_KUPO_2                                              = 10803,  -- That's all there is to it, kupo! Your partner seems to already be participating in the game. If you want to play together, ask your partner to cancel the current game and talk to a moogle again!
