        HAVE_YOU_EVER_HEARD_OF_BLITZ_BUFFALO_KUPO                                     = 10820,  -- Have you ever heard of Blitz Buffalo, kupo? It's a fast and frenzied buffalo-chasing fiasco ferried in from a land to the far west of Quon!
        WE_MOOGLES_THOUGHT_IT_SOUNDED_LIKE_FUN_SO                                     = 10821,  -- We moogles thought it sounded like fun! So we rounded up a bunch of buffalos and set them loose in several places, kupo!
        ALSO_WE_VE_TIED_AN_ITEM_TO_EACH                                               = 10822,  -- Also, we've tied an item to each buffalo! Anyone who catches one can keep the item as a reward! It's a great opportunity for adventurers, kupo!
        BUT_THE_BUFFALOS_AREN_T_GOING_TO_TAKE                                         = 10823,  -- But the buffalos aren't going to take a bunch of frantic adventurers chasing them lightly! You may have to knock one out before it yields its precious item, kupo!
        IF_YOU_MANAGE_TO_LAY_YOUR_HANDS_ON                                            = 10824,  -- If you manage to lay your hands on a buffalo, you better prepare to be flung around, kupo... Kupohoho`.
