        I_HAVE_TRAVELED_HERE_AT_THE_BEHEST_OF                                         = 12083,  -- I have traveled here at the behest of a certain personage from this nation who is well aware of my skill in such matters.
        THE_REQUEST_IS_FAIRLY_ROUTINE_I_AM_TO                                         = 12084,  -- The request is fairly routine--I am to banish the spirits that have suddenly appeared within the town. But there is a problem...
        THESE_GHOSTS_ARE_NOT_SIMPLE_APPARITIONS                                       = 12085,  -- These ghosts are not simple apparitions.
