        MOST_EXCELLENT_THERE_IS_ONE_THING_YOU_MUST                                    = 12094,  -- Most excellent. There is one thing you must be aware of, however.
        THESE_SPIRITS_WERE_ONCE_PEOPLE_SUCH_AS_YOU                                    = 12095,  -- These spirits were once people such as you and I. If they see you directly, there is a good chance they will see through your disguise.
        IF_BY_CHANCE_YOUR_DISGUISE_FAILS_YOU_SIMPLY                                   = 12096,  -- If, by chance, your disguise fails you, simply assume a monstrous form once again and continue your pursuit.
        I_AM_AWARE_OF_TWO_SPIRITS_THAT_HAUNT                                          = 12097,  -- I am aware of two spirits that haunt this town.
        THE_ONE_KNOWN_AS_GUWANANA_IS_THE_MOST                                         = 12098,  -- The one known as Guwanana is the most alert and suspicious, so I will ask you to first track down the Mithran spirit by the name of Bikho Ronpotteh.
        ONCE_YOU_HAVE_A_CLEAR_IDEA_OF_WHY                                             = 12099,  -- Once you have a clear idea of why the ghost has appeared here, I want you to report your findings to me immediately.
