        THIS_IS_A_HAT_MODELED_AFTER_THOSE_WORN                                        = 12106,  -- This is a hat modeled after those worn by the Dark Lilies. Perhaps you might wear it during the season's festivities. Enjoy yourself, and forget about this sorrowful affair.
        HOWEVER_SHOULD_YOU_WISH_TO_AID_IN_ANOTHER                                     = 12107,  -- However, should you wish to aid in another exorcism, I would welcome your help.
