        FOR_WHAT_I_HAPPEN_TO_HAVE_A_CERTAIN                                           = 12120,  -- For what? I happen to have a certain level of fame as an exorcist. You know--a banisher of spirits.
        BUT_THESE_SPIRITS_ARE_PROVING_TO_BE_A                                         = 12121,  -- But these spirits are proving to be a bit of a handful.
