        THIS_LIGHTWEIGHT_GRASS_SADDLE_CAN_CREATE_A_MARKED                             = 14152,  -- This lightweight grass saddle can create a marked improvement in physical performance. However, a chocobo will require some degree of discernment to reap its benefits.
        THIS_LIGHTWEIGHT_COTTON_SADDLE_CAN_CREATE_A_MARKED                            = 14153,  -- This lightweight cotton saddle can create a marked improvement in physical performance. However, a chocobo will require some degree of discernment to reap its benefits.
