        INNINGS_BREAKDOWN_BASE_GIL_PLUS_A_GIL_BONUS                                   = 14354,  -- innings Breakdown # base gil plus a #-gil bonus # [chocobuck/chocobucks] # [solo victory point/solo victory points]
        TURN_IN_YOUR_YES_NO                                                           = 14355,  -- Turn in your %? Yes. No.
        VERY_WELL_HERE_IS_YOUR_BACK                                                   = 14356,  -- Very well. Here is your % back.
