        WE_D_ALSO_APPRECIATE_YOUR_HELP_IN_DISTRIBUTING                                = 15463,  -- We'd also appreciate your help in distributing cards, kupo. All you're required to do is deliver this card to the addressee. We're counting on you!
        THINGS_HAVE_SETTLED_DOWN_FOR_THE_TIME_BEING                                   = 15464,  -- Things have settled down for the time being. But we may have need for your help later on, so don't wander too far away, kupo.
        GREETINGS_FRIEND_I_AM_A_SYNERGY_ENGINEER_DISPATCHED                           = 15465,  -- Greetings, friend! I am a synergy engineer, dispatched from the Institute to maintain the furnaces you see beside me. I also have knowledge and services to share with fellow synergists, if that is what you desire.
        I_SEE_FROM_THE_PUZZLED_EXPRESSION_ON_YOUR                                     = 15466,  -- I see from the puzzled expression on your face that you are unfamiliar with our discipline. To use these furnaces, you will first need to obtain %.
        PIQUED_YOUR_CURIOSITY_HAVE_I_THEN_YOU_SHOULD                                  = 15467,  -- Piqued your curiosity, have I? Then you should speak with Hildolf, our institute director, at his laboratory in the Bastok Metalworks. He's always eager to welcome a new synergist to our ranks.
        MAY_I_BE_OF_SERVICE_NOT_NOW_LEARN                                             = 15468,  -- May I be of service? Not now. Learn recipes. Check fewell. Replenish fewell. Purchase materials. Receive training. Trade cinder. Get information.
        RECIPES_YOU_SAY_LET_S_SEE_WHAT_WE                                             = 15469,  -- Recipes, you say? Let's see what we have that's suitable for your level of expertise...
        I_M_SORRY_I_M_AFRAID_THERE_S                                                  = 15470,  -- ...I'm sorry. I'm afraid there's nothing I can teach you at the moment.
        I_VE_GOT_IT_HOW_ABOUT_MIND_YOU                                                = 15471,  -- I've got it! How about %? Mind you, it'll require a certain level of skill...
        SYNERGY_SKILL                                                                 = 15472,  -- Synergy skill: [Amateur/Recruit/Initiate/Novice/Apprentice/Journeyman/Craftsman/Artisan/Adept/Veteran].
        SKILL                                                                         = 15473,  -- [Fishing/Woodworking/Smithing/Goldsmithing/Clothcraft/Leathercraft/Bonecraft/Alchemy/Cooking/Fishing] skill: [Amateur/Recruit/Initiate/Novice/Apprentice/Journeyman/Craftsman/Artisan/Adept/Veteran/Expert].
        SKILL_SKILL                                                                   = 15474,  -- [Fishing/Woodworking/Smithing/Goldsmithing/Clothcraft/Leathercraft/Bonecraft/Alchemy/Cooking/Fishing] skill: [Amateur/Recruit/Initiate/Novice/Apprentice/Journeyman/Craftsman/Artisan/Adept/Veteran/Expert]. [Fishing/Woodworking/Smithing/Goldsmithing/Clothcraft/Leathercraft/Bonecraft/Alchemy/Cooking/Fishing] skill: [Amateur/Recruit/Initiate/Novice/Apprentice/Journeyman/Craftsman/Artisan/Adept/Veteran/Expert].
        SKILL_SKILL_SKILL                                                             = 15475,  -- [Fishing/Woodworking/Smithing/Goldsmithing/Clothcraft/Leathercraft/Bonecraft/Alchemy/Cooking/Fishing] skill: [Amateur/Recruit/Initiate/Novice/Apprentice/Journeyman/Craftsman/Artisan/Adept/Veteran/Expert]. [Fishing/Woodworking/Smithing/Goldsmithing/Clothcraft/Leathercraft/Bonecraft/Alchemy/Cooking/Fishing] skill: [Amateur/Recruit/Initiate/Novice/Apprentice/Journeyman/Craftsman/Artisan/Adept/Veteran/Expert]. [Fishing/Woodworking/Smithing/Goldsmithing/Clothcraft/Leathercraft/Bonecraft/Alchemy/Cooking/Fishing] skill: [Amateur/Recruit/Initiate/Novice/Apprentice/Journeyman/Craftsman/Artisan/Adept/Veteran/Expert].
        SKILL_SKILL_SKILL_SKILL                                                       = 15476,  -- [Fishing/Woodworking/Smithing/Goldsmithing/Clothcraft/Leathercraft/Bonecraft/Alchemy/Cooking/Fishing] skill: [Amateur/Recruit/Initiate/Novice/Apprentice/Journeyman/Craftsman/Artisan/Adept/Veteran/Expert]. [Fishing/Woodworking/Smithing/Goldsmithing/Clothcraft/Leathercraft/Bonecraft/Alchemy/Cooking/Fishing] skill: [Amateur/Recruit/Initiate/Novice/Apprentice/Journeyman/Craftsman/Artisan/Adept/Veteran/Expert]. [Fishing/Woodworking/Smithing/Goldsmithing/Clothcraft/Leathercraft/Bonecraft/Alchemy/Cooking/Fishing] skill: [Amateur/Recruit/Initiate/Novice/Apprentice/Journeyman/Craftsman/Artisan/Adept/Veteran/Expert]. [Fishing/Woodworking/Smithing/Goldsmithing/Clothcraft/Leathercraft/Bonecraft/Alchemy/Cooking/Fishing] skill: [Amateur/Recruit/Initiate/Novice/Apprentice/Journeyman/Craftsman/Artisan/Adept/Veteran/Expert].
        AS_FOR_MATERIALS_YOU_LL_BE_NEEDING                                            = 15477,  -- As for materials, you'll be needing...
