        AND_THE_REQUIRED_ELEMENTAL_BALANCE_IS_5                                       = 15486,  -- And the required elemental balance is: [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]#.
        AND_THE_REQUIRED_ELEMENTAL_BALANCE_IS_6                                       = 15487,  -- And the required elemental balance is: [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]#.
