        AND_THE_REQUIRED_ELEMENTAL_BALANCE_IS_8                                       = 15489,  -- And the required elemental balance is: [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]# [/oo /o!/o"/o#/o$/o%/o&]#.
        THERE_YOU_GO_THAT_DOESN_T_SOUND_SO                                            = 15490,  -- There you go. That doesn't sound so hard, now, does it?
        BUT_OF_COURSE_IF_YOU_LL_JUST_ALLOW                                            = 15491,  -- But of course! If you'll just allow me to inspect your % for a moment...
        YOUR_FEWELL_SUPPLY_WOULD_APPEAR_TO_BE_AS                                      = 15492,  -- Your fewell supply would appear to be as follows: o o # o!# o"# o## o$# o%# o&#.
        RUNNING_LOW_WE_CAN_FILL_YOU_UP_FOR                                            = 15493,  -- Running low? We can fill you up for a nominal fee.
        REPLENISH_FEWELL_YES_NO                                                       = 15494,  -- Replenish fewell? Yes. No.
        LOOKING_FOR_A_FEWELL_FILL_UP_YOU_SAY                                          = 15495,  -- Looking for a fewell fill-up, you say? Then you've come to the right place!
        HM_WHY_YOUR_TANK_IS_ALREADY_FULL_TO                                           = 15496,  -- ...Hm? Why, your tank is already full to bursting. Come back again if you need a refill.
        NOW_LET_S_SEE_HERE_ACCORDING_TO_MY                                            = 15497,  -- Now let's see here... According to my calculations, I can fill you up to capacity for # gil. How does that sound?
        PAY_GIL_DEAL_NO_THANKS                                                        = 15498,  -- Pay # gil? Deal! No thanks.
        UNDERSTOOD_TAKE_CARE_TO_MONITOR_YOUR_RESERVES_CLOSELY                         = 15499,  -- Understood. Take care to monitor your reserves closely, lest you run out of fewell in the midst of a crucial procedure.
        I_M_AFRAID_YOU_HAVEN_T_THE_REQUISITE                                          = 15500,  -- I'm afraid you haven't the requisite gil, friend. Perhaps another time.
        EXCELLENT_NOW_WE_JUST_POP_OPEN_YOUR_HERE                                      = 15501,  -- Excellent! Now we just pop open your % here, and...
        THERE_YOU_GO_FILLED_TO_THE_BRIM_WITH                                          = 15502,  -- There you go. Filled to the brim with a fresh batch of fewell! Can you smell those fumes? Mmm-mmm!
        YOUR_HAS_BEEN_FILLED_TO_CAPACITY                                              = 15503,  -- Your % has been filled to capacity!
        YOU_HAND_THE_SYNERGY_ENGINEER_GIL                                             = 15504,  -- You hand the synergy engineer # gil.
        HOW_DO_YOU_EXPECT_ME_TO_DO_THAT                                               = 15505,  -- How do you expect me to do that when your % is sitting inside a furnace, friend? You'll have to come back after you've finished synergizing.
        MATERIALS_YOU_SAY_BUT_OF_COURSE_HAVE_A                                        = 15506,  -- Materials, you say? But of course! Have a look at our selection.
        PURCHASE_SOMETHING_NOT_TODAY_GIL_GIL_GIL                                      = 15507,  -- Purchase something? Not today. # : # gil. # : # gil. # : # gil.
        FOR_THAT_COMES_TO_GIL                                                         = 15508,  -- For # , that comes to # gil.
        AH_ANOTHER_DEDICATED_SYNERGIST_LOOKING_TO_REFINE_HIS                          = 15509,  -- Ah, another dedicated synergist looking to refine his/her] technique. Excellent! That motivation will serve you well.
        BUT_I_M_AFRAID_YOU_LL_NEED_EXPERIENCE                                         = 15510,  -- ...But I'm afraid you'll need [/ever so slightly more/a bit more/more/a good deal more/considerably more] experience before you're ready to benefit from my training.
        AND_YES_IT_WOULD_SEEM_YOU_RE_AT                                               = 15511,  -- And yes, it would seem you're at just the right skill level to receive my training. So, what will it be? Which technique would you like to improve?
        TRAIN_IN_WHICH_TECHNIQUE_CANCEL_FEWELL_FEEDING_CURRENT                        = 15512,  -- Train in which technique? Cancel. Fewell feeding. (Current Lv.: #) Furnace thwacking. (Current Lv.: #) Pressure handle. (Current Lv.: #) Safety lever. (Current Lv.: #) Furnace repair. (Current Lv.: #) Fewell recycling. (Current Lv.: #)
        YOU_WISH_TO_IMPROVE_YOUR_TECHNIQUE_IS_THIS                                    = 15513,  -- You wish to improve your [/fewell feeding/furnace thwacking/pressure handle operation/safety lever operation/furnace repair/fewell recycling] technique. Is this correct?
        IT_WOULD_SEEM_YOUR_TECHNIQUE_ALREADY_EXCEEDS_MY                               = 15514,  -- It would seem your [/fewell feeding/furnace thwacking/pressure handle operation/safety lever operation/furnace repair/fewell recycling] technique already exceeds my own. There is no more I can teach you.
        TRAIN_IN_THIS_TECHNIQUE_YES_NO                                                = 15515,  -- Train in this technique? Yes. No.
        VERY_WELL_NOW_LISTEN_UP_WATCH_CLOSELY_AND                                     = 15516,  -- Very well! Now listen up, watch closely, and try to follow along...
        SEE_YOU_TAKE_THIS_PART_HERE_AND_YES                                           = 15517,  -- ...See, you take this part here, and... Yes, yes...just like that...
        NOW_STEADY_HERE_OR_YOU_LL_BE_PICKING                                          = 15518,  -- ...Now steady here, or you'll be picking exploded furnace shrapnel out of your face for a week! Phew, that was a close one...
        AND_BY_APPLYING_COROLLARY_FIVE_OF_HILDOLF_S                                   = 15519,  -- ...And by applying Corollary Five of Hildolf's Third Theory of Inverse Transfocal Equilibrium, we find that...
        CLINK_CLANK_CLUNK_ER_LET_S_TRY_THAT                                           = 15520,  -- <Clink, clank...clunk> ...Er, let's try that once more...
        SUPERB_A_QUICK_LEARNER_I_SEE_IF_ONLY                                          = 15521,  -- ...Superb! A quick learner, I see. If only all my students were as attentive as you!
        YOUR_TECHNIQUE_INCREASES_TO_LEVEL                                             = 15522,  -- Your [/fewell feeding/furnace thwacking/pressure handle operation/safety lever operation/furnace repair/fewell recycling] technique increases to level #!
        RESEARCH_INTO_THE_COMPOSITION_OF_THE_CINDER_PRODUCED                          = 15523,  -- Research into the composition of the cinder produced as a side effect of synergy just might lead to the next breakthrough in our field. Provide us with samples for analysis, and we will gladly reward your contributions.
        TRADE_IN_YOUR_CINDER_CURRENTLY_PZ_NOT_NOW                                     = 15524,  -- Trade in your cinder? (Currently: # Pz) Not now. %: # Pz. %: # Pz. %: # Pz. %: # Pz. %: # Pz. %: # Pz. %: # Pz. # gil: # Pz.
        THIS_IS_WHAT_YOU_WANT_CORRECT                                                 = 15525,  -- This is what you want, correct?
        MAKE_THE_EXCHANGE_YES_NO                                                      = 15526,  -- Make the exchange? Yes. No.
        IT_WOULD_APPEAR_THAT_YOU_LACK_THE_NECESSARY                                   = 15527,  -- It would appear that you lack the necessary quantity of cinder for that transaction.
        EXCELLENT_AND_THIS_IS_YOURS_MAY_IT_SERVE                                      = 15528,  -- Excellent! And this is yours. May it serve you well!
        YOU_TRANSFERRED_PZ_OF_CINDER_TO_THE_SYNERGY                                   = 15529,  -- You transferred # Pz of cinder to the synergy engineer. # Pz [remains/remain] in your possession.
        ASK_ABOUT_WHAT_NOTHING_SYNERGY_FURNACES_SYNERGY_OVERVIEW                      = 15530,  -- Ask about what? Nothing. Synergy furnaces. Synergy overview. Synergy procedure. Synergy recipes. Fewell replenishment. Materials for sale. Synergy techniques. Trading cinder.
        THE_SYNERGY_FURNACES_YOU_SEE_AROUND_TOWN_ARE                                  = 15531,  -- The synergy furnaces you see around town are provided as a public service by the Bastokan Institute of Synergy Research, to ensure that no synergist is ever far away from the tools of their trade.
        THE_SYNERGIST_MUST_PROVIDE_HIS_OR_HER_OWN                                     = 15532,  -- The synergist must provide his or her own %, as well as any materials to be used in the synergy process. Provided those conditions are met, synergy furnaces may be used free of charge.
        NEEDLESS_TO_SAY_ONLY_ONE_PARTY_MAY_OPERATE                                    = 15533,  -- Needless to say, only one party may operate any given furnace at once.
        FORTUNATELY_THERE_ARE_MULTIPLE_FURNACES_INSTALLED_THROUGHOUT_TOWN             = 15534,  -- Fortunately, there are multiple furnaces installed throughout town. If the furnace before you is already in use, please seek out an unused one elsewhere, or wait patiently for your turn.
        YOU_MAY_THINK_OF_SYNERGY_AS_AN_EVOLVED                                        = 15535,  -- You may think of synergy as an evolved form of synthesis. It is a discipline full of heretofore unimagined possibilities, but one which demands consummate skill from its practitioners.
        LIKE_SYNTHESIS_SYNERGY_INVOLVES_COMBINING_MATERIALS_ACCORDING_TO              = 15536,  -- Like synthesis, synergy involves combining materials according to a prescribed recipe to yield oft-spectacular results. The rub is that each synergy recipe also dictates a certain elemental balance that must be achieved for the procedure to be successful.
        THIS_BALANCE_IS_ACHIEVED_THROUGH_SKILLFUL_INFUSION_OF                         = 15537,  -- This balance is achieved through skillful infusion of combustible elemental crystals that we synergists call fewell. To begin the synergy process, you'll have to feed the furnace with fewell and get those flames burning!
        AS_A_GENERAL_RULE_THE_MORE_COMPLEX_THE                                        = 15538,  -- As a general rule, the more complex the recipe, the more fewell it will require. Take care to check your stock before you fire up the furnace, lest you find its flames guttering out at a crucial moment.
        WITH_THE_BELLY_OF_THE_FURNACE_ROARING_UP                                      = 15539,  -- With the belly of the furnace roaring up a storm, it's time to toss in your materials and start synergizing! Keep a close eye on the balance of elements and deploy fewell as necessary. Approach the prescribed elemental balance, and your item will take form, allowing you to remove it from the furnace.
        THE_CLOSER_YOU_ARE_TO_THE_IDEAL_ELEMENTAL                                     = 15540,  -- The closer you are to the ideal elemental balance, the higher the quality of your finished product will be. In synergy, it pays to be a perfectionist!
        BUT_BE_FOREWARNED_THESE_FURNACES_CAN_ONLY_SUSTAIN                             = 15541,  -- But be forewarned: these furnaces can only sustain the elemental maelstrom swirling and storming inside them for so long.
        IF_THE_FURNACE_S_DURABILITY_SHOULD_FAIL_THE                                   = 15542,  -- If the furnace's durability should fail, the synergy process will be interrupted, and you will be forced to start anew.
        TAKE_HEART_THOUGH_AS_ANY_MATERIALS_INSIDE_YOUR                                = 15543,  -- Take heart, though, as any materials inside your % will remain intact. You may retrieve them or attempt the synergy process again as you see fit.
        ANY_FEWELL_CONSUMED_IN_THE_FAILED_SYNERGY_ATTEMPT                             = 15544,  -- Any fewell consumed in the failed synergy attempt, on the other hand, will be permanently lost.
        SYNERGISTS_MUST_ALSO_BE_WARY_OF_DEBRIS_BUILDUP                                = 15545,  -- Synergists must also be wary of debris buildup, an unavoidable side effect of the volatile elemental reactions that take place within the synergy furnace.
        SHOULD_TOO_MUCH_DEBRIS_BE_ALLOWED_TO_ACCUMULATE                               = 15546,  -- Should too much debris be allowed to accumulate, the contents of the furnace will become unstable, potentially leading to unpleasant explosions and eruptions. Such accidents pose considerable risk to the synergy attempt in progress, as well as the physical well-being of the synergist, so be sure to exercise due caution!
        YOU_MAY_BE_ASKING_YOURSELF_WHY_HOW_IN                                         = 15547,  -- You may be asking yourself, Why, how in the name of Hildolf am I going to oversee all of these complicated procedures and variables by myself?
        HERE_S_THE_GOOD_NEWS_YOU_DON_T                                                = 15548,  -- Here's the good news: you don't have to! For you see, synergy furnaces are designed for use by multiple operators.
        THE_MORE_COMPLEX_THE_RECIPE_THE_GREATER_LEVEL                                 = 15549,  -- The more complex the recipe, the greater level of skill and hands-on manipulation it will demand. At such times, it would be in your best interest to seek out like-minded synergists and take on the challenge together.
        FINALLY_IT_WOULD_BE_REMISS_OF_ME_NOT                                          = 15550,  -- Finally, it would be remiss of me not to make mention of %, the curious substance whose properties are only now--with the emergence of synergy--becoming known to us.
        THOUGH_THERE_IS_MUCH_YET_TO_BE_LEARNED                                        = 15551,  -- Though there is much yet to be learned, our research has revealed that % may be used to bolster your equipment, if attached in a proper manner.
        MIND_YOU_IS_NOT_EASY_TO_COME_BY                                               = 15552,  -- Mind you, % is not easy to come by, and I can offer no clues as to where or how to obtain it. Should you be fortunate enough to come across some in your travels, however, I encourage you to explore its potential.
        SYNERGY_IS_NOT_A_DISCIPLINE_FOR_THE_FAINT                                     = 15553,  -- Synergy is not a discipline for the faint of heart or mind, but with dedication and cooperation, there are great rewards to be reaped. May your career as a synergist prove fruitful!
        FIRST_YOU_LL_BE_WANTING_TO_CHECK_YOUR                                         = 15554,  -- First, you'll be wanting to check your fewell supply. You may do so by speaking with a synergy engineer such as myself, or by examining a synergy furnace.
        YOU_LL_BE_NEEDING_AT_LEAST_ONE_UNIT                                           = 15555,  -- You'll be needing at least one unit of fewell for each element dictated by your recipe. Without this, even the most skilled synergist cannot hope to succeed.
        SHOULD_YOUR_FEWELL_SUPPLY_BE_IN_ORDER_IT                                      = 15556,  -- Should your fewell supply be in order, it's time to proceed with the synergy. If you are using one of these public synergy furnaces here, you'll need to examine it and lay claim to its use.
        YOU_MAY_THEN_DEPOSIT_YOUR_INGREDIENTS_SHOULD_THEY                             = 15557,  -- You may then deposit your ingredients. Should they correspond to a proper recipe, the synergy furnace will fire up automatically. Note that as a safety precaution, the furnace will not activate if the recipe is beyond your level of synergy skill.
        FROM_HERE_IT_BECOMES_A_RACE_AGAINST_THE                                       = 15558,  -- From here, it becomes a race against the clock! Through skilled operation of the synergy furnace, you must achieve the elemental balance prescribed by the recipe before the furnace's durability fails.
        FORTUNATELY_SYNERGY_FURNACES_ARE_OUTFITTED_WITH_A_WIDE                        = 15559,  -- Fortunately, synergy furnaces are outfitted with a wide array of features designed to aid the synergist in this demanding task. First, you'll want to confirm the current balance of elements within the furnace and compare it to your desired result.
        NEXT_YOU_CAN_BEGIN_TO_FEED_FEWELL_INTO                                        = 15560,  -- Next, you can begin to feed fewell into the furnace to gradually raise the level of elemental concentration. Feeding fewell into the furnace until the required elemental balance is achieved is the most fundamental operation of synergy.
        HOWEVER_HIGH_CONCENTRATIONS_OF_ELEMENTAL_POWER_CAN_LEAD                       = 15561,  -- However, high concentrations of elemental power can lead to volatile and unpredictable reactions. Simply adding fewell haphazardly without making the necessary adjustments is a recipe for only one thing, and that's disaster.
        IF_YOU_SENSE_THAT_THE_FURNACE_IS_ON                                           = 15562,  -- If you sense that the furnace is on the verge of elemental overload, you'll want to employ the safety lever and pressure handle to prevent an unfortunate accident from occurring.
        YOU_LL_ALSO_WANT_TO_MIND_THE_LAWS                                             = 15563,  -- You'll also want to mind the laws of elemental ascendancy and opposition. Increasing the concentration of a particular element will cause its counterpart to decrease.
        THE_FURNACE_CANNOT_SUSTAIN_ITS_POWER_INDEFINITELY_AND                         = 15564,  -- The furnace cannot sustain its power indefinitely, and will gradually lose durability as the synergy process continues. You'll need to perform periodic furnace repair should the furnace near its breaking point.
        IT_IS_ALSO_POSSIBLE_TO_RECYCLE_STREWN_FEWELL                                  = 15565,  -- It is also possible to recycle strewn fewell during synergy. While this will not impact the success or failure of the process itself, it will result in a greater amount of salvageable cinder produced as a by-product.
        THIS_CINDER_IS_OF_GREAT_INTEREST_TO_OUR                                       = 15566,  -- This cinder is of great interest to our researchers back at the institute. As such, we have introduced a reward system through which quality samples can be traded in for an assortment of synergy-related wares.
        AS_MARVELOUS_AN_APPARATUS_AS_THE_SYNERGY_FURNACE                              = 15567,  -- As marvelous an apparatus as the synergy furnace may be, keep in mind that the technology is still in its infancy, and highly unstable. There may be times when accidents occur despite the best efforts of the synergist.
        FOR_YOUR_SAFETY_WE_RECOMMEND_STEPPING_AS_FAR                                  = 15568,  -- For your safety, we recommend stepping as far away from the furnace as possible at the first sign of danger. Some synergists claim that giving the furnace a good thwack is also effective in preventing such accidents, but this is pure madness, if you ask me!
        YOU_WILL_ALSO_FIND_THAT_THERE_ARE_NUMEROUS                                    = 15569,  -- You will also find that there are numerous techniques that can be applied to make the synergy procedure go even more smoothly.
        IN_MANY_CASES_EXPERTISE_AND_KNOWLEDGE_ACQUIRED_THROUGH                        = 15570,  -- In many cases, expertise and knowledge acquired through crafting will serve you in synergy as well. To truly master synergy, one must master crafting as well.
        NOW_LET_US_RETURN_TO_THE_SYNERGY_PROCESS                                      = 15571,  -- Now let us return to the synergy process itself. As your elemental balance approaches that prescribed by the recipe, the furnace will signal you, and you may retrieve your finished product.
        IF_THE_FURNACE_IS_STILL_HOLDING_STRONG_AT                                     = 15572,  -- If the furnace is still holding strong at this time, you may choose to keep working to achieve an even closer balance. The closer you come to the ideal balance, the higher the quality of your finished product will be.
        INDEED_MANY_SYNERGY_MASTERS_CONSIDER_THESE_WANING_MOMENTS                     = 15573,  -- Indeed, many synergy masters consider these waning moments after the signal to be the time to really show off their skills! Why, if they manage to achieve an elemental surge...
        WHAT_S_AN_ELEMENTAL_SURGE_YOU_ASK_WHY                                         = 15574,  -- What's an elemental surge, you ask? Why, it's a miraculous phenomenon that occurs rarely--ever so rarely--upon feeding the furnace fewell.
        THE_ELEMENTS_REACT_JUST_IN_THE_RIGHT_WAY                                      = 15575,  -- The elements react just in the right way, creating a miraculous reaction that brings the level of elemental concentration to exactly the desired level. Truly a boon from the Goddess for any synergist, no?
        AND_THAT_IS_THE_SYNERGY_PROCESS_IN_A                                          = 15576,  -- ...And that is the synergy process in a nutshell. There's quite a bit of information to take in, so don't hesitate to return any time for a refresher course.
        MUCH_LIKE_SYNTHESIS_TO_FASHION_ITEMS_THROUGH_SYNERGY                          = 15577,  -- Much like synthesis, to fashion items through synergy, you will need to follow a recipe. We synergy engineers are always unearthing new recipes, and are happy to share with you those suitable for your level of skill.
        UNLIKE_SYNTHESIS_HOWEVER_A_SYNERGY_RECIPE_IS_MORE                             = 15578,  -- Unlike synthesis, however, a synergy recipe is more than just a list of ingredients. There is also a required elemental balance that must be attained to achieve your desired result.
        SIMPLE_RECIPES_INVOLVE_ONLY_SMALL_DOSES_OF_A                                  = 15579,  -- Simple recipes involve only small doses of a limited number of elements, but more complex ones require the synergist to skillfully juggle wide ranges of elements in extremely high concentrations.
        THE_INGREDIENTS_YOU_WILL_HAVE_TO_REMEMBER_ON                                  = 15580,  -- The ingredients, you will have to remember on your own. The required elemental balance, however, may be reviewed at any time during the synergy process by observing the readings on the synergy furnace.
        IN_PARTICULAR_RECIPES_THROUGH_WHICH_THE_CURIOUS_SUBSTANCE                     = 15581,  -- In particular, recipes through which the curious substance known as % can be attached to equipment are creating quite a buzz among synergistically inclined adventurers these days.
        CANNOT_BE_ATTACHED_DIRECTLY_FIRST_EQUIPMENT_MUST_BE                           = 15582,  -- % cannot be attached directly. First, equipment must be prepared by etching an aperture into which an elementally compatible piece of % can then be embedded.
        THE_TYPE_OF_APERTURE_THAT_MAY_BE_ETCHED                                       = 15583,  -- The type of aperture that may be etched will depend on the piece of equipment. There are also pieces of equipment that, alas, may not be modified at all.
        IF_YOU_ARE_CURIOUS_WHAT_MANNER_OF_APERTURE                                    = 15584,  -- If you are curious what manner of aperture may be etched into a particular piece of equipment, you need only trade it to me or one of my colleagues.
        AS_A_GENERAL_RULE_THE_HIGHER_THE_LEVEL                                        = 15585,  -- As a general rule, the higher the level of the item in question, the more difficult the synergy process for creating an aperture will be.
        YOU_WILL_FIND_THAT_CERTAIN_PIECES_OF_EQUIPMENT                                = 15586,  -- You will find that certain pieces of equipment may be etched with multiple apertures. It is, however, only possible to create one aperture at a time.
        ETCHING_REQUIRES_THE_USE_OF_A_CORROSIVE_SUBSTANCE                             = 15587,  -- Etching requires the use of a corrosive substance we call mordant. Deposit mordant into a synergy furnace along with your equipment, and the process will begin.
        MY_COLLEAGUES_AND_I_HAVE_A_STOCK_OF                                           = 15588,  -- My colleagues and I have a stock of mordant available for sale. The best way to learn is to practice, so if you're curious, we encourage you to purchase some and begin experimenting!
        THE_DIFFICULTY_OF_THE_SYNERGY_PROCESS_WHEN_EMBEDDING                          = 15589,  -- The difficulty of the synergy process when embedding evolith is decided by a number of factors.
        SUCH_FACTORS_INCLUDE_THE_VARIETY_OF_APERTURE_AND                              = 15590,  -- Such factors include the variety of aperture and evolith, as well as the quantity of evolith you seek to attach. Embedding the first piece is not too difficult a task, but the second and third pieces will not go in so easily.
        TO_BEGIN_THE_EMBEDDING_PROCESS_DEPOSIT_YOUR_EVOLITH                           = 15591,  -- To begin the embedding process, deposit your evolith into the synergy furnace along with a piece of equipment with a compatible aperture.
        WHEN_ETCHING_OR_EMBEDDING_THE_REQUIRED_ELEMENTAL_BALANCE                      = 15592,  -- When etching or embedding, the required elemental balance may be confirmed at any time during the synergy process, so let this be your guide.
        SHOULD_YOU_EVER_WISH_TO_REMOVE_ANY_APERTURES                                  = 15593,  -- Should you ever wish to remove any apertures and embedded evolith from a piece of equipment entirely, you may do so with an ingredient we call revertant.
        TOSS_THE_REVERTANT_IN_A_SYNERGY_FURNACE_ALONG                                 = 15594,  -- Toss the revertant in a synergy furnace along with your equipment, and its potent powers will restore your item to a pure and pristine state! Be warned, however, that embedded evolith will be lost forever in the process.
        AS_YOU_ARE_NO_DOUBT_ALREADY_AWARE_SYNERGY                                     = 15595,  -- As you are no doubt already aware, synergy makes use of a highly combustible form of elemental crystals that we call fewell. The more complex the recipe, the greater the quantity of fewell required.
        VETERAN_SYNERGISTS_KNOW_WELL_THE_HASSLE_OF_HAVING                             = 15596,  -- Veteran synergists know well the hassle of having to constantly monitor their fewell supply and procure crystals to replenish depleted stock.
        TO_FREE_YOU_OF_SUCH_TRIFLING_BURDENS_AND                                      = 15597,  -- To free you of such trifling burdens and allow you to focus your mind entirely on your art, we synergy engineers are offering a convenient fewell replenishment service!
        FOR_A_NOMINAL_FEE_CALCULATED_BASED_UPON_THE                                   = 15598,  -- For a nominal fee calculated based upon the current state of your fewell reserves, we will instantly refill you to full capacity.
        THAT_S_RIGHT_ALL_ELEMENTS_IN_ONE_SIMPLE                                       = 15599,  -- That's right--all elements in one simple transaction, directly to your %! What could be easier?
        LOOKING_TO_FIRE_UP_YOUR_FURNACE_AND_ENTER                                     = 15600,  -- Looking to fire up your furnace and enter the world of %? If so, you've come to the right place!
        WE_RE_PROUD_TO_OFFER_A_SUPPLY_OF                                              = 15601,  -- We're proud to offer a supply of the corrosive agent known as mordant for sale. With this, synergy newcomers can hone their skills and outfit their equipment with evolith-capable apertures in the process.
        MIND_YOU_OUR_STOCK_IS_LIMITED_TO_ONLY                                         = 15602,  -- Mind you, our stock is limited to only the most diluted, readily produced form of the stuff. You'll find that it only has the strength to etch items of relatively low level.
        ETCHING_HIGH_POWERED_EQUIPMENT_REQUIRES_THE_USE_OF                            = 15603,  -- Etching high-powered equipment requires the use of more concentrated and potent forms of mordant. As quantities are limited, we can offer these only in exchange for cinder.
        AH_SYNERGY_TECHNIQUES_THOSE_HANDY_TRICKS_OF_THE                               = 15604,  -- Ah, synergy techniques! Those handy tricks of the trade that can mean the difference between a shiny new item and a major furnace meltdown.
        MY_COLLEAGUES_AND_I_ARE_ALWAYS_EAGER_TO                                       = 15605,  -- My colleagues and I are always eager to train fellow synergists in a wide range of techniques. We can't do it all, though--you'll need to hone your synergy skill in order to benefit from our instruction.
        BEAR_IN_MIND_THAT_CERTAIN_TECHNIQUES_CAN_ONLY                                 = 15606,  -- Bear in mind that certain techniques can only be imparted to students possessing specialized crafting knowledge. For example, only skilled smiths will be able to comprehend the method for more efficient fewell feeding.
        ACCOMPLISHED_GOLDSMITHS_WILL_BE_ABLE_TO_OBSERVE_THE                           = 15607,  -- Accomplished goldsmiths will be able to observe the inner workings of the furnace and stave off potential accidents. You will find that all crafting skills--even those you may not expect--may be applied in some way to support the synergy process.
        WORD_HAS_IT_THAT_THERE_ARE_ALSO_PIECES                                        = 15608,  -- Word has it that there are also pieces of equipment that can impart hidden synergy techniques to the wearer. These, too, are said to be only accessible to skilled crafters.
        THE_MORAL_OF_THE_STORY_IS_THIS_WHILE                                          = 15609,  -- The moral of the story is this: while synergy skill is important, neglect not your other crafting skills. To become a true synergy master, finding the proper balance is key.
        SYNERGY_REMAINS_A_YOUNG_DISCIPLINE_AND_RESEARCHERS_BACK                       = 15610,  -- Synergy remains a young discipline, and researchers back at the institute are burning the midnight fewell in the hopes of uncovering the next breakthrough in our field.
        RESEARCH_OF_LATE_IS_CENTERED_AROUND_THE_CINDER                                = 15611,  -- Research of late is centered around the cinder that is left behind as a by-product of each synergy operation. Their composition, it would seem, has much to teach us of the true nature of the complex elemental reactions that go on within the bellies of these furnaces.
        WE_VE_EVEN_INSTITUTED_A_REWARD_PROGRAM_FOR                                    = 15612,  -- We've even instituted a reward program for adventurers willing to contribute prime samples in the name of science.
        IT_WOULD_BE_NO_EXAGGERATION_TO_SAY_THAT                                       = 15613,  -- It would be no exaggeration to say that, to us, cinder is worth more than its weight in gold! Bring it to me or my colleagues--preferably in large quantities--and you're sure to be pleased at what we can offer you in return.
        WONDERING_IF_YOUR_CAN_BE_OUTFITTED_WITH_EVOLITH                               = 15614,  -- Wondering if your % can be outfitted with evolith, are you? Well, you've come to the right place!
        A_QUICK_LOOK_AT_ITS_COMPOSITION_SHOULD_TELL                                   = 15615,  -- A quick look at its composition should tell us all we need to know. Let's see here...
        CONGRATULATIONS_YOUR_CAN_INDEED_HOLD_EVOLITH_APERTURE_A                       = 15616,  -- Congratulations! Your % can indeed hold [an/another] evolith aperture. A %-shaped aperture, to be exact...
        SUITABLE_FOR_EVOLITH_OF_THE_FOLLOWING_SIZE_AND                                = 15617,  -- ...Suitable for evolith of the following size and elemental affinity: Maximum size: # / [/oo /o!/o"/o#/o$/o%/o&].
        SUITABLE_FOR_EVOLITH_OF_THE_FOLLOWING_SIZES_AND                               = 15618,  -- ...Suitable for evolith of the following sizes and elemental affinities: Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&]. Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&].
        SUITABLE_FOR_EVOLITH_OF_THE_FOLLOWING_SIZES_AND_2                             = 15619,  -- ...Suitable for evolith of the following sizes and elemental affinities: Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&]. Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&]. Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&].
        SUITABLE_FOR_EVOLITH_OF_THE_FOLLOWING_SIZES_AND_3                             = 15620,  -- ...Suitable for evolith of the following sizes and elemental affinities: Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&]. Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&]. Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&]. Maximum size: # / Affinity: [/oo /o!/o"/o#/o$/o%/o&].
        THAT_IS_ALL_SHOULD_YOU_WISH_TO_HAVE                                           = 15621,  -- That is all. Should you wish to have any other pieces of equipment analyzed, you know where to find us.
        HMM_I_M_AFRAID_YOUR_CANNOT_HOUSE_ANY                                          = 15622,  -- Hmm... I'm afraid your % cannot house any more apertures.
        ALAS_IT_S_A_SHAME_BUT_IT_APPEARS                                              = 15623,  -- ...Alas. It's a shame, but it appears your % cannot be etched.
        HMM_WHAT_S_THIS_IT_WOULD_SEEM_THAT                                            = 15624,  -- Hmm, what's this? It would seem that your % cannot be etched at this time.
        DO_YOU_LOVE_SYNERGIZING_AS_MUCH_AS_I                                          = 15625,  -- Do you love synergizing as much as I love synergizing!? 'Cause if you do, you're gonna loooooove the recipes I have for you!
        VIEW_RECIPES_FOR_WHICH_SKILL_LEVEL_ACTUALLY_NEVER                             = 15626,  -- View recipes for which skill level? Actually, never mind. Amateur. Recruit. Initiate. Novice. Apprentice. Journeyman. Craftsman. Artisan. Adept. Veteran.
        BROWSE_TO_WHICH_PAGE_CANCEL_PAGE_PAGE_PAGE                                    = 15627,  -- Browse to which page? Cancel. Page [1/9/17/25/33/41/49/57/65/73/81/89/97/105/113/121]. Page [2/10/18/26/34/42/50/58/66/74/82/90/98/106/114/122]. Page [3/11/19/27/35/43/51/59/67/75/83/91/99/107/115/123]. Page [4/12/20/28/36/44/52/60/68/76/84/92/100/108/116/124]. Page [5/13/21/29/37/45/53/61/69/77/85/93/101/109/117/125]. Page [6/14/22/30/38/46/54/62/70/78/86/94/102/110/118/126]. Page [7/15/23/31/39/47/55/63/71/79/87/95/103/111/119/127]. Page [8/16/24/32/40/48/56/64/72/80/88/96/104/112/120/128]. Previous page. Next page.
        VIEW_WHICH_RECIPE_P_NONE_RETURN_TO_PAGE                                       = 15628,  -- View which recipe? ([Amateur/Recruit/Initiate/Novice/Apprentice/Journeyman/Craftsman/Artisan/Adept/Veteran], p. #). None. %. %. %. %. %. %. %. %. Return to page selection. Previous page. Next page.
        OH_THE_WHY_THAT_S_ONE_OF_MY                                                   = 15629,  -- Oh, the %? Why, that's one of my favorite recipes, too! What skills does it require? Let's see here...
        WELL_LOOK_AT_THIS_ALL_YOU_NEED_IS                                             = 15630,  -- Well, look at this. All you need is a furnace and your own Goddess-given synergy skills to make that one! Ain't synergy grand?
        WAIT_NO_DON_T_TELL_ME_YOU_STRIKE                                              = 15631,  -- Wait! No, don't tell me. You strike me as a man/woman] who's looking to learn a thing or two about synergy.
        LEARN_ABOUT_SYNERGY_NOT_TODAY_TEACH_ME_JUST                                   = 15632,  -- Learn about synergy? Not today. Teach me! Just give me %.
        A_LIFE_WITHOUT_INTELLECTUAL_CURIOSITY_IS_A_LIFE                               = 15633,  -- A life without intellectual curiosity is a life hardly worth living. Should your eyes one day open to this truth, you are free to return.
        I_THOUGHT_YOU_D_NEVER_ASK_SYNERGY_IS                                          = 15634,  -- I thought you'd never ask! Synergy is both an art and a science: an evolution--nay, a revolution--in synthesis.
        USING_IN_CONJUNCTION_WITH_A_SYNERGY_FURNACE_THE                               = 15635,  -- Using % in conjunction with a synergy furnace--the apparatus you see beside me--the synergist wields the power of myriad elements to fabricate a veritable host of potent items.
        WHAT_WE_CALL_SERVES_TO_DISPENSE_FEWELL_CRYSTALS                               = 15636,  -- What we call % serves to dispense fewell crystals--the lifeblood of the synergy process--whilst also protecting its contents from the volatile reactions that occur within the bowels of the furnace.
        SYNERGY_FURNACES_HAVE_BEEN_INSTALLED_THROUGHOUT_THE_CITY                      = 15637,  -- Synergy furnaces have been installed throughout the city for the use of all synergists. The crucible is sufficiently compact and lightweight that you can carry it with you.
        INITIATING_THE_SYNERGY_PROCESS_IS_AS_SIMPLE_AS                                = 15638,  -- Initiating the synergy process is as simple as inserting your % into a furnace and commencing the infusion of elemental fewell.
        NEEDLESS_TO_SAY_WHAT_WILL_HAPPEN_FROM_THERE                                   = 15639,  -- Needless to say, what will happen from there is not quite so simple.
        SUCCESSFUL_SYNERGY_IS_CONTINGENT_UPON_MAINTAINING_ELEMENTAL_EQUILIBRIUM       = 15640,  -- Successful synergy is contingent upon maintaining elemental equilibrium. The prescribed ratio, of course, will vary depending on the artifact you are attempting to create.
        YOU_CAN_INCREASE_THE_RATIO_OF_A_PARTICULAR                                    = 15641,  -- You can increase the ratio of a particular element by burning the corresponding variety of fewell.
        BUT_HEREIN_LIES_THE_RUB_SYNERGY_IS_A                                          = 15642,  -- But herein lies the rub: synergy is a still young science, and the technology we employ remains, shall we say...unstable.
        A_BIT_TOO_MUCH_FEWELL_HERE_A_WRONG                                            = 15643,  -- A bit too much fewell here, a wrong lever pulled there, and the percolating pot will explode, spitting scalding elemental guck every which way to Firesday.
        THAT_S_WHY_SMART_SYNERGISTS_SYNERGIZE_IN_NUMBERS                              = 15644,  -- That's why smart synergists synergize in numbers. Too many culinarians might spoil the broth, but when it comes to synergy, it's the more the merrier!
        AN_ASPIRING_SYNERGIST_I_SEE_IF_YOU_RE                                         = 15645,  -- An aspiring synergist, I see! If you're looking for %, you've certainly come to the right place.
        I_CAN_SELL_YOU_A_SPLENDID_ENTRY_LEVEL                                         = 15646,  -- I can sell you a splendid entry-level model for # gil. A small price to pay to embark on a lifelong journey of scientific discovery, wouldn't you say?
        GIL_PAID_IN_FULL                                                              = 15647,  -- # gil, paid in full!
        AS_PROMISED_HERE_S_YOUR_AND_BECAUSE_I                                         = 15648,  -- As promised, here's your %. And because I like your enthusiasm, I've even stocked it to the brim with fewell for you! How's that for a deal?
        THE_SYNERGIST_MUST_PROVIDE_HIS_OR_HER_OWN_2                                   = 15649,  -- The synergist must provide his or her own %, as well as any materials to be used in the synergy process. Synergy furnaces themselves may be used free of charge.
        SHOULD_YOU_WISH_TO_LEARN_MORE_ABOUT_THE                                       = 15650,  -- Should you wish to learn more about the science of synergy, seek out one of the engineers stationed throughout the town.
        A_SUPER_SPECIAL_STARLIGHT_CELEBRATION_TO_YOU_AMBITIOUS                        = 15651,  -- A super-special Starlight Celebration to you, ambitious adventurer!
        WHAT_AM_I_SAYING_THIS_IS_HARDLY_THE                                           = 15652,  -- What am I saying!? This is hardly the time for gleeful greetings or alliterative addresses, kupo!
        EVEN_AS_WE_SPEAK_OVERZEALOUS_GOBLINS_ARE_PARTAKING                            = 15653,  -- Even as we speak, overzealous Goblins are partaking not just in the Starlight Celebration spirit, but others' precious presents! These Gobbies bear no bad blood, but their covetous capers are the cause of much consternation, kupo.
        AND_TO_MAKE_MATTERS_WORSE_THEY_VE_EVEN                                        = 15654,  -- And to make matters worse, they've even filched the furnishings the MHMU ordered from the guilds... I know the saying, If you give a Goblin goulash... but this is just rikupulous!
        PLEASE_I_BESEECH_YOU_FIND_THE_GOBLINS_TRAIPSING                               = 15655,  -- Please, %, I beseech you! Find the Goblins traipsing about town and teach them the meaning of private property once and for all! (By affably asking them to relinquish what they requisitioned, kupo.)
        IT_MAY_SEEM_LIKE_THE_MHMU_IS_JUST                                             = 15656,  -- It may seem like the MHMU is just exploiting the nearest adventurer, but nay! You--and only you--are capable of restoring resplendence and revelry to the realm. Now go forth and fulfill the festive fate we thrust upon you, kupo!
        KUPOPOPO_HAVE_YOU_FORGOTTEN_YOUR_MERRY_MISSION_ALREADY                        = 15657,  -- Kupopopo! Have you forgotten your merry mission already? Get giddy, gift-grabbing Goblins around town to give back people's goods, then go gab to a Moogle when you're done.
        AND_REMEMBER_GOBBIES_LIKE_TO_STICK_THEIR_NOSES                                = 15658,  -- And remember, Gobbies like to stick their noses in other creatures' business, if you know what I mean. Snuff out your smell so they can't sense your spoils, kupo.
        AND_REMEMBER_GOBLINS_GO_CUCKOO_FOR_COMESTIBLES_KUPO                           = 15659,  -- And remember, Goblins go cuckoo for comestibles, kupo. Offer them their favorite food, for they should forget you even exist.
        AND_REMEMBER_GOBLINS_JUST_WANT_TO_JUMP_FOR                                    = 15660,  -- And remember, Goblins just want to jump for joy and jubilation at this jocular time of year. Bequeath beastmen bills or bedazzling bijoux to them and you may find yourself furnished with furnishings in return, kupo.
        GREAT_GLORIOUS_GODDESS_YOU_VE_MANAGED_TO_PROCURE                              = 15661,  -- Great glorious Goddess, you've managed to procure a present! Praise be to your positively prodigious persistence! ...And your altruistic attitude after you return it to its rightful remitter, kupo!
        IT_LOOKS_LIKE_THIS_GIFT_IS_FROM_SOMEONE                                       = 15662,  -- It looks like this gift is from someone named %. Seek out the sender and start spreading some Starlight spirit, kupo! Oh, and watch out for mischievous Goblin mitts, my little gofer--I mean adventurer!
        WONDERFUL_WORK_WARDEN_OF_WEAL_HOWEVER_SINCE_GIVING                            = 15663,  -- Wonderful work, warden of weal! However, since giving is greater than receiving, how about giving % word that you were able to deliver the present?
        THE_CONSIDERABLE_AMOUNT_OF_CHARITY_YOU_VE_SHOWN                               = 15664,  -- The considerable amount of charity you've shown complete strangers cannot be overstated, kupo. Without your magnanimity, moxie, and master mediation skills, this year's Starlight Celebration would have been a much dimmer affair.
        YET_TO_POLISH_THIS_PARTY_TO_THE_POINT                                         = 15665,  -- Yet to polish this party to the point of pristine luster, more Goblins must be taught the difference between naughty and nice! Remember, once you give back a gift, seal the deal by simply sauntering over to the nearest moogle. We're counting on you, kupo!
        THE_MHMU_HUMBLY_OFFERS_YOU_THIS_TOKEN_OF                                      = 15666,  -- The MHMU humbly offers you this token of our thanks, not only for making the world a brighter place, but for tolerating our moogle mummery and the voluminous vats of verbosity that violated your virgin ears.
        OH_DEAR_OH_DEAR_OH_DEAR_I_FORGOT                                              = 15667,  -- Oh dear, oh dear, oh dear! I forgot those festive Gobbies are still frolicking with our furnishings, kupo!
        I_M_SO_SORRY_TO_SOLICIT_FURTHER_FAVORS                                        = 15668,  -- I'm so sorry to solicit further favors from you, but could you kindly retrieve those as well? Pretty please with paprika on top? You wouldn't want to keep us from rewarding the good boys and girls of Vana'diel, would you, kupo?
        KUPO_HO_HO_DO_MY_DETERIORATING_EYES_DECEIVE                                   = 15669,  -- Kupo ho ho! Do my deteriorating eyes deceive me, or is that one of the furnishings we ordered? We'd planned on giving them all to needy orphans, but you've done so much for the MHMU recently, why don't you have this one? 'Tis the season, so they say.
        WHAT_AN_ASTOUNDING_ACCOMPLISHMENT_AS_EXPECTED_OF_AN                           = 15670,  -- What an astounding accomplishment, as expected of an adventurer like you! We are eternally grateful for the copious kindnesses you've conferred upon us, kupo.
        WORD_AROUND_THE_UNION_FOUNTAIN_IS_THAT_OTHER                                  = 15671,  -- Word around the union fountain is that other nations' furnishings still remain at large. Would it be too terrible a torment to traipse around town--peepers peeled for gregarious Gobbies ogling purported presents--the next time you visit another nation? The MHMU would be forever in your debt, kupo.
        WHEEEW_WAY_TO_WHISK_THAT_ONE_UNDER_THE                                        = 15672,  -- (Wheeew, way to whisk that one under the rug. I could never tell him/her] that we got distracted by the dazzling decorations and had the furnishings nabbed from nigh under our noses!)
        HAPPY_TOY_HAPPY_TOY_WHERE_BE_ME_HAPPY                                         = 15673,  -- Happy toy, happy toy, where be me happy toy?t
        EV_RY_GIRL_EV_RY_BOY_EV_RYBODY                                                = 15674,  -- Ev'ry girl, ev'ry boy, ev'rybody, happy toy! Me nose holes smell the joy, The joy from happy toy! Wheeere cooould iiit beee?t
        THIS_FOR_ME_IN_DOO_BID_ABLY_COULD                                             = 15675,  -- This for me? In-doo-bid-ably! Could be gooder, but it not bad.
        WAAAH_IT_YOU_YOU_GIVE_YUM_YUMS_FOR                                            = 15676,  -- Waaah! It you! You give yum-yums for me tum-tum. Good guy/girl]!
        NOT_FOR_US_NOT_FOR_ME_I_GIVE                                                  = 15677,  -- Not for us, not for me? I give it back. Now you happy? Happy toy, happy toy, where be me happy toy?t
        NO_NO_NO_NO_NO_GO_AWAY_NOSE                                                   = 15678,  -- No no no no no! Go away! Nose holes busy sniff for happy toy!
        ID_15679                                                                      = 15679,  -- ...
        YOU_HAVE_FRIEND_YOU_DO_WE_GOBBIES_HAVE                                        = 15680,  -- You have friend, you do? We Gobbies have friend too.
        YUM_YUMS_FOR_ME_GOBBIES_REMEMBER_TILL_OUR                                     = 15681,  -- Yum-yums for me? Gobbies remember...till our tummies go rumble-rumble again.
        FOR_ME_WHY_GIVE_SO_NICE_THING_TO                                              = 15682,  -- For me!? Why give so nice thing to me!? Me so happy head go boom! So boom! But first, me need give happy toy to you too.
        HAPPY_TOY_FOR_ME_WHY_YOU_GIVE_SO                                              = 15683,  -- Happy toy? For me? Why you give so good thing to me? But no can take. Me have no happy toy for you.
        BLECH_WHAT_THIS_YUCKY_THING_IT_MAKE_ME                                        = 15684,  -- Blech. What this yucky thing? It make me want upgut food. Take it away.
        WHAT_BUT_HOW_IF_THAT_S_TRULY_FROM                                             = 15685,  -- What? But how...? If that's truly from %, that must mean...you stole it and you're ransoming it back to me! If you think for one moment that I'd pay scum like you, you'd best think twice!
        OH_I_SEE_MY_APOLOGIES_HOW_SILLY_OF                                            = 15686,  -- Oh, I see. My apologies. How silly of me. Everyone knows how mischievous Goblins get during the Starlight Celebration season. I read somewhere that it's got something to do with the moon and the tides or whatnot.
        ANYWAY_SORRY_TO_TROUBLE_YOU_BUT_COULD_YOU                                     = 15687,  -- Anyway, sorry to trouble you, but could you deliver this in my stead? I may look like a strapping young lad, but I have this illness that prevents me from doing the same task twice in one day. Quite troublesome, really.
        ALSO_COULD_YOU_DO_ME_A_FAVOR_AND                                              = 15688,  -- Also, could you do me a favor and report back to me after you're done? I didn't want to spend the extra gil for delivery confirmation with times as tough as they are, you know?
        I_TAKE_IT_YOU_DELIVERED_MY_PRESENT_SAFE                                       = 15689,  -- I take it you delivered my present safe and sound? Oh, and it was well received, too? Ha, you didn't need to tell me that, for my gifts are always a hit. I guess I should thank you though, seeing as how you played a tiny part in my Starlight Celebration success.
        WAAAH_A_CUTTHROAT_TAKE_ANYTHING_YOU_WANT_JUST                                 = 15690,  -- Waaah, a cutthroat! Take anything you want, just not my lucky chocobo hose, please! I... Wait, isn't that the gift I sent %? You didn't steal that too, did you!?
        WHAT_YOU_VALIANTLY_WRESTED_IT_FROM_THE_CLUTCHES                               = 15691,  -- What!? You...valiantly wrested it from the clutches of a greedy Goblin so you could return it to me? I just knew my handsome champion/fair handmaiden] in resplendent regalia would come some day!
        I_M_SURE_YOU_VE_BEEN_THROUGH_QUITE                                            = 15692,  -- I'm sure you've been through quite a few trials and tribulations just getting this back to me, your fair lady. However, my hands are tied at the moment and I can't take this present to %. Therefore, I command you, my loyal follower, to act as my liaison and deliver it unscathed. I have no doubt that you'll succeed, since a knight/handmaiden] will do anything to serve and protect his/her] mistress.
        AND_PLEASE_DON_T_FORGET_TO_CHECK_IN                                           = 15693,  -- And please don't forget to check in with me after the delivery is made. Every champion/handmaiden] knows that's the chivalrous/proper] thing to do.
        HOW_FARED_YOUR_JOURNEY_MY_COURAGEOUS_CHAMPION_HUMBLE                          = 15694,  -- How fared your journey, my courageous champion/humble handmaiden]? Oh, I simply knew I could place my complete trust in you! You've not only made your fair lady quite proud, but saved the Starlight Celebration from those covetous beastmen! Oh, joyous day!
        I_BEG_YOUR_PARDON_BUT_I_CANNOT_HELP                                           = 15695,  -- I beg your pardon, but I cannot help but notice that this is the parcel I sent to %. How might you have come by it?
        AH_I_SEE_THOSE_GOBLIN_RAPSCALLIONS_STILL_SHOW                                 = 15696,  -- Ah, I see. Those Goblin rapscallions still show a complete and utter disregard for social graces, would you not agree? At any rate, you seem to possess a rather strong sense of justice, and for that I am most grateful.
        COULD_YOU_ALSO_FIND_IT_WITHIN_YOUR_HEART                                      = 15697,  -- Could you also find it within your heart to see that this package reaches % safely? I may be a man of humble means, but you will certainly have my eternal gratitude and undying admiration.
        OH_MY_THIS_UTTERLY_SLIPPED_MY_ADDLED_MIND                                     = 15698,  -- Oh my. This utterly slipped my addled mind. I am truly sorry, but I fear I must heap one more request upon your already burdened back. Could you please report back to me after you've made the delivery? It would undoubtedly lessen the anxiety weighing down my fragile heart.
        GODDESS_BE_GOOD_YOU_HAVE_RETURNED_AND_WITH                                    = 15699,  -- Goddess be good, you have returned! And with favorable tidings, no? Splendid. Absolutely splendid. Thanks to you, I feel as if I could burst into a Starlight carol at any moment. Fa-la-la-la`t.
        WHAT_DOTH_BRING_THEE_FORE_THESE_RHEUMY_EYES                                   = 15700,  -- What doth bring thee 'fore these rheumy eyes, orbs that pierce the soul and a stranger's guise? Harken, thou hast %'s present, from whom hast thou received such consent?
        TIS_AN_ENTERTAINING_TALE_WITH_WHICH_THY_JOWLS                                 = 15701,  -- 'Tis an entertaining tale with which thy jowls doth flail, A tale of Goblins run amok, and wretched me bereft of luck. Still, thanks are in store for completing this chore with a dearth of gore.
        WHILE_THESE_NEXT_WORDS_MAY_CONJURE_A_STORM                                    = 15702,  -- While these next words may conjure a storm, I cannot assist thee in any form. Thus, I entreat thee to heed the call...deliver this gift to % once and for all!
        FORE_I_FINISH_THIS_LENGTHY_TIRADE_ONE_LAST                                    = 15703,  -- 'Fore I finish this lengthy tirade, one last request must be made. Once the gift hath changed hands, return at once for further plans.
        THOU_HAST_SAFELY_RETURNED_FROM_THY_TRIAL_UPON                                 = 15704,  -- Thou hast safely returned from thy trial? Upon us both doth Altana smile! To thee, the savior of the Starlight Celebration, I do give heartfelt acclamations!
        WH_WH_WHAT_HAVE_YOU_GOT_THERE_IT                                              = 15705,  -- Wh-wh-what have you got there? It looks awfully-wafully like the gift I gave to %. Did something happen? P-p-please don't tell me that % passy-wassed away!
        IT_WAS_JUST_A_G_G_GOBLIN_PRANK                                                = 15706,  -- ...It was just a G-g-goblin prank? Sorry to overreactaru. I had a t-t-traumatic experience last Starlight Devastation--er, Celebration! So now I always feary-wear the worst. By the way, th-th-thank you for getting my gift back.
        AS_YOU_CAN_GUESS_M_M_MY_COMFORT                                               = 15707,  -- As you can guess, m-m-my comfort zone is rather itty-bitty. I know you must be expired--tired! But can you please helpy-welp me and deliver my present to %?
        AFTER_YOU_PASS_ON_THE_GIFT_PASS_THE                                           = 15708,  -- After you pass on--the gift! Pass the gift on! Then c-c-could you report back to me? I truly-wuly want to know how % reacts.
        AH_YOU_RE_BACK_IT_S_S_MOST                                                    = 15709,  -- Ah, you're back! It's %'s most perished, er, cherished possession, you say? Wh-wh-what lofty-wofty praise! I can't thank you enough for your c-c-contributions, adventurer.
        SO_MANY_NASTY_WASTY_THINGS_HAPPENED_TO_ME                                     = 15710,  -- So many nasty-wasty things happened to me today, I'm just too moody-woody to listen to your blather! Begone before I--wait, isn't that my present to %?
        UGH_QUIT_BARKING_LIKE_A_BOG_DOG_BROTHER                                       = 15711,  -- Ugh, quit barking like a bog dog, brother-wother/sister-wister]! I don't give a ham and cheese about giddy Goblins or lazy moogles.
        YOU_THINK_YOU_RE_SO_GREAT_BECAUSE_YOU                                         = 15712,  -- You think you're so great because you saved my present from some baddie-waddies? Bah humbug-wumbug! If you're gonna stick your nosey-wose in others' business, then you bettaru finish what you started! You'll be taking that gift on over to %, I tell you what!
        AND_DON_T_THINK_FOR_A_MINUTE_WINUTE                                           = 15713,  -- And don't think for a minute-winute that I'm going to let you get away with ruining my day! Report back here for a tongue-lashing when you're done! Now get going before I gutaru you right here and now!
        HMPH_SO_YOU_RE_STUPID_AS_WELL_AS                                              = 15714,  -- Hmph, so you're stupid as well as rude? Are you so subservient that you'd actually come backy-wack for a beating? Get out of my face! You disgustaru me. Oh, and Merry Starlight!
        HEY_I_SENT_THAT_TO_WHY_DO_YOU                                                 = 15715,  -- Hey, I sent that to %. Why do you have it?
        HMMM_STOLEN_BY_GOBBIES_HUH_THANKS_FOR_GETTING                                 = 15716,  -- Hmmm. Stolen by Gobbies, huh? Thanks for getting it back.
        SORRY_TO_BURDEN_YOU_BUT_COULD_YOU_BRING                                       = 15717,  -- Sorry to burden you, but could you bring it to % again for me?
        ALSO_I_D_LIKE_IT_IF_YOU_COULD                                                 = 15718,  -- Also, I'd like it if you could please fill me in when you're done.
        I_SEE_YOU_VE_RETURNED_MMM_THAT_S                                              = 15719,  -- I see you've returned. Mmm...that's good news indeed. Thank you for the kindness you've shown me and my friend.
        WHAT_HAVE_WE_HERE_A_CAT_BURRRGLAR_HOW                                         = 15720,  -- What have we here? A cat burrrglar? How dare you despoil the innocent people of our fair nation!
        WHAT_AM_I_TALKING_ABOUT_THAT_S_THE                                            = 15721,  -- What am I talking about? That's the prrresent I sent %! How could you have it if you didn't steal it!?
        OH_I_SEE_YOU_RE_A_DEFENDER_OF                                                 = 15722,  -- Oh, I see. You're a defender of justice too. Good job negotiating with those Goblin scum. I just hope that rrrepeating that story to everyone you've saved hasn't got you hacking up hairballs.
        BUT_ENOUGH_TAIL_WAGGING_I_HAVE_SOME_PREY                                      = 15723,  -- But enough tail wagging. I have some prey I need to take care of, so could you rrredeliver that gift to % and report back to me when you're done?
        WHAT_TIMING_I_VE_JUST_RRRETURNED_FROM_MY                                      = 15724,  -- What timing! I've just rrreturned from my own mission. Whew, good thing % liked it! That little trinket was as high priced as the hair on a cat's back! Anyway, thanks for your help. If your fur ever gets rubbed the wrong way, give me a sign and I'll come rrroaring to the rescue!
        A_PRESENT_FROM_OH_GLORIOUS_DAY_THIS_IS                                        = 15725,  -- A present...from %? Oh, glorious day! This is for all those times I never got a present and kept telling myself next year will be the one.
        I_M_AT_A_LOSS_FOR_WHAT_TO                                                     = 15726,  -- I'm at a loss for what to say! I'm just overwhelmed with a waterfall of emotion! Thank you so much!
        AND_PLEASE_THANK_THE_NEXT_TIME_YOU_SEE                                        = 15727,  -- And please thank % the next time you see that good samaritan. The person who said, 'Tis better to give than receive probably never had a gift drought as long as mine. I feel fantastic!
        OH_IS_THAT_A_PRESENT_FROM_YOU_SAY                                             = 15728,  -- Oh, is that...a present? From %, you say?
        UGH_IT_FIGURES_DID_IT_COME_WITH_A                                             = 15729,  -- Ugh, it figures. Did it come with a card that says something pathetic like I've died a thousand deaths drowning in the depths of your eyes? That scoundrel has been stalking me ever since we happened to meet one day on a boat to Buburimu Peninsula.
        I_M_ACTUALLY_QUITE_FED_UP_WITH_THESE                                          = 15730,  -- I'm actually quite fed up with these ridiculous baubles, but I'm not one for losing face. If you should see % again, please give my regards and say I found the gift rather...quaint.
        WHAT_S_THIS_A_PRESENT_ADDRESSED_TO_ME                                         = 15731,  -- What's this? A present addressed to me from %?
        HOW_UNEXPECTEDLY_CHARMING_AND_THOUGHTFUL_THIS_HAS_CERTAINLY                   = 15732,  -- How unexpectedly charming and thoughtful. This has certainly brightened what was about to be a gloomy Starlight Celebration.
        WOULD_YOU_BE_SO_KIND_AS_TO_TELL                                               = 15733,  -- Would you be so kind as to tell % that I truly appreciate the gift? I am also thoroughly impressed with your selfless nature, adventurer.
        COULD_IT_BE_INDEED_IT_IS_BENEVOLENCE_MANIFEST                                 = 15734,  -- Could it be...? Indeed, it is benevolence manifest, emanating from the humble home of one %?
        WHAT_A_DECIDEDLY_PLEASANT_SURPRISE_I_AM_SIMPLY                                = 15735,  -- What a decidedly pleasant surprise. I am simply beside myself with an unbridled, childish glee that has not washed over me in ever so long. I swear that I am on the brink of giggling like I used to when I was still knee-high to a Taru.
        THE_FINITE_WORDS_OF_US_MERE_MORTALS_MAY                                       = 15736,  -- The finite words of us mere mortals may not be sufficient to convey the depths of my gratitude, but I earnestly hope % would appreciate a succinct Thank you.
        A_PRESENT_FROM_THIS_ISN_T_ONE_OF                                              = 15737,  -- A present from...%? This isn't one of those tricky-wicky flimflams, is it?
        OF_COURSE_I_LL_TAKE_IT_I_M                                                    = 15738,  -- Of course I'll take it! I'm not one to look a gift horse in the mouth, even if it's from my mortaru enemy! Maybe % has turned over a new leaf since we last met...
        WELL_THEN_I_SUPPOSE_SOME_THANKS_ARE_IN                                        = 15739,  -- Well then, I suppose some thanks are in order. But if I find out that this was just some elaborataru scheme to make me lower my guard, I'm going to boppy-wop you both in the noggin!
        OOOH_A_GIFT_FROM_WHAT_JOLLY_WOLLY_TIDINGS                                     = 15740,  -- Oooh, a gift from %? What jolly-wolly tidings you've brought, adventurer.
        I_WONDER_WHAT_S_INSIDE_COULD_IT_BE                                            = 15741,  -- I wonder what's inside... Could it be a scrum-diddly-umptious cake? But I've already gotten so roly-poly during the holiday season! Maybe I should just send it back!
        NO_THATARU_WOULDN_T_BE_RIGHT_BESIDES_IT                                       = 15742,  -- No, thataru wouldn't be right. Besides, it might not be edible. Anyway, please be sure to thank % for pudding the icing on such a delectable Starcake Chocolation. Ugh, I'm just terrible!
        WHY_WOULD_BE_SENDING_ME_A_GIFT_IT                                             = 15743,  -- Why would % be sending me a gift? It's not like there's anything special going on.
        THE_STARLIGHT_CELEBRATION_YOU_SAY_SO_THAT_EXPLAINS                            = 15744,  -- The Starlight Celebration, you say? So that explains the light shows and festive atmosphere around here lately. My head just hasn't been the same since I fell off that chocobo last month.
        I_BEST_START_LOOKING_FOR_SOMETHING_TO_GIVE                                    = 15745,  -- I best start looking for something to give in return. In the meantime, please tell % how happy I am to have received this. And maybe next year I'll remember before it's too late. <Sigh>...One can only hope.
        A_PRESENT_FOR_ME_I_M_A_LONE                                                   = 15746,  -- A present for me? I'm a lone lioness, and I don't need to share my kills with anyone!
        WHAT_WANTED_ME_TO_HAVE_THIS_WELL_I                                            = 15747,  -- What? % wanted me to have this? Well, I guess I could take it...
        DON_T_GET_THE_WRRRONG_IDEA_IT_S                                               = 15748,  -- Don't get the wrrrong idea! It's not like I enjoy the gift or anything! Just run back to % and drop dead! This conversation never happened!
        YOU_HAVE_RECEIVED                                                             = 15749,  -- You have received %!
        YOUR_HAS_BEEN_TAKEN                                                           = 15750,  -- Your % has been taken!
        YOU_HANDED_OVER                                                               = 15751,  -- You handed over %.
        GREETINGS_AND_WELL_MET_I_AM_A_VOIDWATCH                                       = 15752,  -- Greetings and well met. I am a Voidwatch scientist charged with researching the potential uses of atmacite.
        THOSE_WHO_POSSESS_MAY_COME_TO_ME_TO                                           = 15753,  -- Those who possess % may come to me to have their hard-won atmacite infused. Stratum abyssite also falls within my domain, so present to me any whose properties you wish to have analyzed.
        AH_I_M_ALSO_AUTHORIZED_TO_TELEPORT_FOLK                                       = 15754,  -- Ah, I'm also authorized to teleport folk to operation sites. Quite versatile, aren't I?
        I_BEG_OF_YOU_FRIEND_LEND_US_YOUR                                              = 15755,  -- I beg of you, friend. Lend us your stout sword arm in the fight to protect Vana'diel from the Voidwalker threat.
        WHAT_WILL_YOU_DO_NOTHING_FOR_NOW_HAVE                                         = 15756,  -- What will you do? Nothing for now. Have stratum abyssite examined. Request teleportation. Analyze atmacite. Ask about atmacite. Ask about atmacite enrichment.
        WHAT_WILL_YOU_DO_NOTHING_FOR_NOW_INFUSED                                      = 15757,  -- What will you do? Nothing for now. Infused: % (lv.#) Infused: % (lv.#) Infused: % (lv.#) Purge atmacite. Infuse atmacite. Enrich atmacite.
        INFUSE_WHICH_ATMACITE_CRUOR_NONE_FOR_NOW_LV                                   = 15758,  -- Infuse which atmacite? (Cruor: #) None for now. % (lv.#) % (lv.#) % (lv.#) % (lv.#) % (lv.#) % (lv.#) % (lv.#) % (lv.#) % (lv.#) % (lv.#) % (lv.#) % (lv.#) Previous page. Next page.
        INFUSING_THE_LV_REQUIRES_CRUOR                                                = 15759,  -- Infusing the % (lv.#) requires # cruor.
        INFUSE_LV_YES_NO                                                              = 15760,  -- Infuse % (lv.#)? Yes. No.
        YOU_DO_NOT_HAVE_ENOUGH_CRUOR_3                                                = 15761,  -- You do not have enough cruor.
        WHICH_ATMACITE_NONE_FOR_NOW_LV_LV_LV                                          = 15762,  -- [Infuse/Purge] which atmacite? None for now. % (lv.#) % (lv.#) % (lv.#)
        PURGE_LV_YES_NO                                                               = 15763,  -- Purge % (lv.#)? Yes. No.
        EXPENDS_CRUOR_AND_IS_NOW_INFUSED_WITH_LV                                      = 15764,  -- % expends # cruor and is now infused with % (lv.#)!
        THE_ATMACITE_COULD_NOT_BE_INFUSED                                             = 15765,  -- The atmacite could not be infused...
        HAS_BEEN_PURGED_OF_THE_LV                                                     = 15766,  -- % has been purged of the % (lv.#).
        PURGES_THE_LV_INFUSING_LV_IN_ITS_PLACE                                        = 15767,  -- % purges the % (lv.#), infusing % (lv.#) in its place. (Cruor expended: #)
        YOU_DO_NOT_POSSESS_ANY_ATMACITE_CAPABLE_OF                                    = 15768,  -- You do not possess any atmacite capable of enrichment.
        ENRICH_WHICH_ATMACITE_CRUOR_NONE_FOR_NOW_LV                                   = 15769,  -- Enrich which atmacite? (Cruor: #) None for now. % (lv.#): # % (lv.#): # % (lv.#): # % (lv.#): # % (lv.#): # % (lv.#): # % (lv.#): # % (lv.#): # % (lv.#): # % (lv.#): # % (lv.#): # % (lv.#): # Previous page. Next page.
        ENRICHING_THE_WILL_PRODUCE_THE_FOLLOWING                                      = 15770,  -- Enriching the % will produce the following:
        ENRICHING_THE_FROM_LEVEL_TO_LEVEL_REQUIRES_CRUOR                              = 15771,  -- Enriching the % from level # to level # requires # cruor.
        ENRICH_YES_NO                                                                 = 15772,  -- Enrich %? Yes. No.
        YOUR_HAS_BEEN_ENRICHED_TO_LEVEL_CRUOR_EXPENDED                                = 15773,  -- Your % has been enriched to level #! (Cruor expended: #)
        THE_HAS_BEEN_ENRICHED_TO_ITS_MAXIMUM_LEVEL                                    = 15774,  -- The % has been enriched to its maximum level!
        THE_ATMACITE_S_ENRICHMENT_LEVEL_FAILED_TO_RISE                                = 15775,  -- The atmacite's enrichment level failed to rise...
        THE_ATMACITE_COULD_NOT_BE_PURGED                                              = 15776,  -- The atmacite could not be purged...
        THE_LV_BESTOWS_THE_FOLLOWING_BONUSES                                          = 15777,  -- The % (lv.#) bestows the following bonuses:
        REPLACE_LV_YES_NO                                                             = 15778,  -- Replace % (Lv.#)? Yes. No.
        ATMACITE_IS_BEST_DESCRIBED_AS_THE_CRYSTALLINE_AGGLOMERATION                   = 15779,  -- Atmacite is best described as the crystalline agglomeration of a creature's soul. Our scientists have succeeded in discovering a way to tap its power to serve the efforts of the Voidwatch.
        BY_INFUSING_ONE_S_BODY_WITH_ATMACITE_IT                                       = 15780,  -- By infusing one's body with atmacite, it is possible to obtain powers akin to those once possessed by the creature whence it came, rather like turning a beast's fangs upon its own kind.
        AT_FIRST_GLANCE_ATMACITE_APPEARS_TO_BE_THE                                    = 15781,  -- At first glance, atmacite appears to be the perfect artificial enhancement. However, it does suffer from a single limitation: its power is unleashed only when engaged in a Voidwatch operation.
        RESEARCH_TO_IDENTIFY_THE_EXACT_REASON_FOR_THIS                                = 15782,  -- Research to identify the exact reason for this continues, but most scientists find the spectral alignment theory compelling.
        THAT_IS_BEING_FORMED_OF_VOIDWALKER_SOULS_ATMACITE                             = 15783,  -- That is, being formed of Voidwalker souls, atmacite will surge to life only when its bearer is existentially aligned to its dimension of origin.
        FROM_THIS_IT_CAN_BE_INFERRED_THAT_VOIDWALKERS                                 = 15784,  -- From this it can be inferred that Voidwalkers are stripped of considerable strength when they cross over into Vana'diel.
        BUT_I_SUSPECT_THIS_IS_OF_LITTLE_INTEREST                                      = 15785,  -- But I suspect this is of little interest to a layman like you. Allow me to return to the subject at hand.
        THE_INFUSION_OF_ATMACITE_REQUIRES_CRUOR_A_POTENT                              = 15786,  -- The infusion of atmacite requires cruor, a potent energy source that takes the form of shiny red granules.
        CRUOR_IS_OBTAINABLE_BY_VARIOUS_MEANS_FELLING_A                                = 15787,  -- Cruor is obtainable by various means, felling a Voidwalker being the most common of all. As you can never have too much cruor, I urge you to be diligent in its procurement.
        WE_VE_RECENTLY_PERFECTED_A_METHOD_FOR_IMPROVING                               = 15788,  -- We've recently perfected a method for improving atmacite potency. The process is called enrichment, and involves fusing cruor on to atmacite to amplify its power.
        ATMACITE_CAN_BE_ENRICHED_IN_STAGES_UP_TO                                      = 15789,  -- Atmacite can be enriched in stages up to a maximum of level #. The quantity of cruor required varies with the variety of atmacite as well as its current enrichment level.
        UNDER_NORMAL_CONDITIONS_ATMACITE_ENRICHMENT_IS_AN_INTENSIVE                   = 15790,  -- Under normal conditions, atmacite enrichment is an intensive process that demands trained hands. For reasons yet to be determined, however, both infusion and enrichment can be safely performed by laymen, provided they're at a planar rift.
        KEEP_THIS_IN_MIND_SHOULD_THE_NEED_ARISE                                       = 15791,  -- Keep this in mind should the need arise to reconfigure your atmacite with haste.
        EXAMINE_WHICH_STRATUM_ABYSSITE_NONE_RIGHT_NOW                                 = 15792,  -- Examine which stratum abyssite? None right now. %. %. %. %. %. %. %.
        HMMM_I_M_AFRAID_THE_STONE_ISN_T                                               = 15793,  -- Hmmm... I'm afraid the stone isn't exhibiting any signs of growth.
        THE_STONE_SHOWS_SIGNS_INDICATIVE_OF_GROWTH_BUT                                = 15794,  -- The stone shows signs indicative of growth, but the changes are yet too slight for untrained eyes to discern.
        OH_MY_SUCH_A_MAGNIFICENT_DISPLAY_OF_EVOLUTION                                 = 15795,  -- Oh my, such a magnificent display of evolution! Leaves absolutely nothing to be desired!
        WHY_YES_THIS_STONE_IS_SHOWING_THE_INITIAL                                     = 15796,  -- Why yes, this stone is showing the initial signs of evolution. It appears there's still room for growth, however.
        HMMM_I_FEAR_THIS_STONE_S_GROWTH_HAS                                           = 15797,  -- Hmmm... I fear this stone's growth has been interrupted. Were you to find a catalyst of sorts, perhaps it could still evolve further?
        HMMM_I_M_AFRAID_THE_STONE_ISN_T_2                                             = 15798,  -- Hmmm... I'm afraid the stone isn't exhibiting any signs of growth. Perhaps a catalyst of sorts could help to spur along the process?
        HOW_CURIOUS_I_VE_NOT_SEEN_A_STONE                                             = 15799,  -- How curious. I've not seen a stone like this before. Wherever did you find it?
        YOUR_HAS_EVOLVED_INTO                                                         = 15800,  -- Your % has evolved into %!
        SUPPLY_ME_WITH_THE_CRUOR_NECESSARY_AND_I                                      = 15801,  -- Supply me with the # cruor necessary, and I shall gladly teleport you to an operation site of your choosing.
        SELECT_VOIDWATCH_JURISDICTION_I_VE_CHANGED_MY_MIND                            = 15802,  -- Select Voidwatch jurisdiction. I've changed my mind. San d'Oria. Bastok. Windurst. Jeuno. Jeuno II. Zilart region. Tavnazia. Aht Urhgan.
        SELECT_YOUR_DESTINATION_NOWHERE_EAST_RONFAURE_EAST_RONFAURE                   = 15803,  -- Select your destination. Nowhere. East Ronfaure. East Ronfaure. Ordelle's Caves (entrance). Jugner Forest. Jugner Forest. King Ranperre's Tomb (entrance).
        SELECT_YOUR_DESTINATION_NOWHERE_NORTH_GUSTABERG_NORTH_GUSTABERG               = 15804,  -- Select your destination. Nowhere. North Gustaberg. North Gustaberg. Gusgen Mines (entrance). Pashhow Marshlands. Pashhow Marshlands. Dangruf Wadi (entrance).
        SELECT_YOUR_DESTINATION_NOWHERE_WEST_SARUTABARUTA_WEST_SARUTABARUTA           = 15805,  -- Select your destination. Nowhere. West Sarutabaruta. West Sarutabaruta. Maze of Shakhrami (entrance). Meriphataud Mountains. Meriphataud Mountains. Outer Horutoto Ruins (entrance).
