        IT_SEEMS_YOU_RE_SHORT_ON_SOLDIER_COME                                         = 16752,  -- It seems you're short on [Conquest Points/Imperial Standing credits/Allied Notes], soldier. Come back when you've got a bit more seasoning under your belt.
        PROCEED_REQUIRED_YES_NO                                                       = 16753,  -- Proceed? (Required [Points/Standing/Notes]: #) Yes. No.
        OBTAINS_IN_EXCHANGE_FOR                                                       = 16754,  -- % obtains % in exchange for # [Conquest Points/credits of Imperial Standing/Allied Notes].
        OBTAINS_IN_EXCHANGE_FOR_2                                                     = 16755,  -- % obtains # % in exchange for # [Conquest Points/credits of Imperial Standing/Allied Notes].
        OBTAINS_IN_EXCHANGE_FOR_3                                                     = 16756,  -- % obtains % in exchange for # [Conquest Points/credits of Imperial Standing/Allied Notes].
