        YOU_ALREADY_HAVE_AND_I_M_NOT_AUTHORIZED                                       = 16758,  -- You already have %, and I'm not authorized to furnish you with another. Resources are in short supply. You'll have to make do with what you've already got.
        HOW_MANY                                                                      = 16767,  -- How many? ( [Conquest Points/Imperial Standing/Allied Notes]: #)
        YOU_MAY_PURCHASE_UP_TO_AT_A_TIME_2                                            = 16768,  -- You may purchase up to # at a time.
        YOU_SEE_THE_FOLLOWING_WORDS_SCRAWLED_UPON_THE                                 = 16769,  -- You see the following words scrawled upon the lid: Free to take.
        WILL_YOU_TAKE_SOMETHING_NOTHING_RIGHT_NOW_PREVIOUS                            = 16770,  -- Will you take something? Nothing right now. %. %. %. %. %. %. %. %. Previous Page. Next Page.
        YOU_PULL_OUT_FOR_CLOSER_INSPECTION                                            = 16771,  -- You pull out % for closer inspection.
        OBTAIN_THIS_ITEM_YES_ON_SECOND_THOUGHT                                        = 16772,  -- Obtain this item? Yes. On second thought...
        WELCOME_TO_THE_MHMU_S_PORTER_SERVICE_KUPO                                     = 16773,  -- Welcome to the MHMU's porter service, kupo! Which of your burdensome belongings shall I take off your hands today?
        DO_SOMETHING_KUPO_PORTER_SERVICE_BUY_A_STORAGE                                = 16774,  -- Do something, kupo? Porter service? Buy a storage slip. No, thank you.
        IS_YOUR_GOBBIEBAG_SPLITTING_AT_THE_SEAMS_MOG                                  = 16775,  -- Is your gobbiebag splitting at the seams? Mog Safe spilling over? Why, an accomplished adventurer like yourself surely has more stuff than you know what to do with.
        THAT_S_WHERE_I_COME_IN_KUPO_I                                                 = 16776,  -- That's where I come in, kupo. I'll gladly hold onto your prized possessions, freeing you space to gather up even grander goodies.
        TO_MAKE_USE_OF_MY_SERVICES_FIRST_YOU                                          = 16777,  -- To make use of my services, first you'll need to buy one of these storage slips for the low, low fee of # gil.
        STORAGE_SLIPS_COME_IN_NUMEROUS_VARIETIES_KUPO_EACH                            = 16778,  -- Storage slips come in numerous varieties, kupo, each corresponding to a different type of item.
        YOU_LL_WANT_TO_PERUSE_THE_FINE_PRINT                                          = 16779,  -- You'll want to peruse the fine print closely, so you don't end up paying good gil for a scrap of parchment useless for the particular item you wish to store.
