        UNITY_LEADER_SPECIFIC_OBJECTIVES_ARE_TIED_TO_THE                              = 17042,  -- Unity leader-specific objectives are tied to the Unity's eponymous leader and change each week.
        WANTED_OBJECTIVES_CENTER_AROUND_VANQUISHING_PARTICULARLY_HEINOUS_FOES         = 17043,  -- Wanted objectives center around vanquishing particularly heinous foes that terrorize Vana'diel.
        THESE_OBJECTIVES_ARE_OF_A_HIGHER_CALIBER_AND                                  = 17044,  -- These objectives are of a higher caliber, and thus require currency known as Unity accolades to undertake.
        SHARED_AND_LEADER_SPECIFIC_OBJECTIVES_PROVIDE_MORE_ACCOLADES                  = 17045,  -- Shared and leader-specific objectives provide more accolades than run-of-the-mill objectives.
        VANA_DIEL_HAS_ALWAYS_BEEN_PLAGUED_BY_NEFARIOUS                                = 17046,  -- Vana'diel has always been plagued by nefarious foes pillaging the landscape, but relatives of some of the more heinous ones have been spotted lately.
        THE_A_M_A_N_HAS_DEEMED_IT                                                     = 17047,  -- The A.M.A.N. has deemed it necessary to eliminate these Wanted targets, and has notified Unity members that they are of the utmost priority.
        A_LIST_OF_THESE_FOES_CAN_BE_VIEWED                                            = 17048,  -- A list of these foes can be viewed at any time by selecting the appropriate subcategory under the objectives list.
        UNITY_CONCORD_REPRESENTATIVES_ARE_ABLE_TO_PROVIDE_PARTICIPANTS                = 17049,  -- Unity Concord representatives are able to provide participants with transportation to the areas where these threats can be found.
        THOUGH_TACKLING_THE_PROFANE_WILL_LIKELY_REQUIRE_PARTICIPATION                 = 17050,  -- Though tackling the profane will likely require participation of your allies, the objective can be undertaken so long as at least one person has set the appropriate objective.
        WHEN_YOU_SET_THE_OBJECTIVE_AND_COMMENCE_THE                                   = 17051,  -- When you set the objective and commence the battle, the requisite number of Unity accolades will be deducted from your total.
        SUCCESSFUL_CHALLENGERS_WILL_BE_REWARDED_WITH_SPECIAL_REWARDS                  = 17052,  -- Successful challengers will be rewarded with special rewards in addition to the normal sparks of eminence.
        NO_UNITY_ACCOLADES_WILL_BE_CHARGED_SHOULD_YOU                                 = 17053,  -- No Unity accolades will be charged should you commence the battle without having the appropriate objective set, but the rewards you can reap from your efforts will be limited.
        YOU_CAN_SNATCH_UNPARALLELED_EQUIPMENT_AND_MATERIALS_FROM                      = 17054,  -- You can snatch unparalleled equipment and materials from the slain corpses of Wanted targets.
        AN_A_M_A_N_SPECIALIST_VERSED_IN                                               = 17055,  -- An A.M.A.N. specialist versed in arcane harmonization has kindly offered to use these materials to bring out the latent potential in such pieces.
        ONE_OF_THE_UNITY_GUIDES_WILL_BE_PLEASED                                       = 17056,  -- One of the Unity guides will be pleased to accept certain combinations of equipment and materials to begin the process for you.
        A_NUMBER_OF_ACCOLADES_IS_REQUIRED_FOR_THIS                                    = 17057,  -- A number of accolades is required for this service, but the precision and accuracy of her methods are without equal, and there is no worry of your equipment being destroyed.
        YOU_CAN_USE_SPECIFIED_MATERIALS_TO_ADD_NEW                                    = 17058,  -- You can use specified materials to add new attributes to equipment that has been upgraded.
        UTILIZING_ADDITIONAL_MATERIALS_AFTER_ADDING_AN_ATTRIBUTE_CAN                  = 17059,  -- Utilizing additional materials after adding an attribute can accumulate Reinforcement Points for the equipment and increase its rank.
        INCREASING_YOUR_EQUIPMENT_S_RANK_CAN_BOOST_ITS                                = 17060,  -- Increasing your equipment's rank can boost its attributes, while some equipment can also have additional attributes added later.
        SPEAK_TO_THE_UNITY_GUIDES_AFTER_GATHERING_THE                                 = 17061,  -- Speak to the Unity guides after gathering the necessary materials for your equipment in order to add attributes to it or increase its rank.
        THE_FIRST_TIME_YOU_ADD_AN_ATTRIBUTE_TO                                        = 17062,  -- The first time you add an attribute to a piece of equipment will require the use of Unity accolades.
        IT_ALSO_REQUIRES_THAT_YOU_FIRST_COMPLETE_A                                    = 17063,  -- It also requires that you first complete a specific Records of Eminence objective.
        THE_WORK_YOU_REQUEST_WILL_BE_CARRIED_OUT                                      = 17064,  -- The work you request will be carried out on-site by a specially trained Unity guide.
        COMPLETING_RECORDS_OF_EMINENCE_OBJECTIVES_AS_PART_OF                          = 17065,  -- Completing Records of Eminence objectives as part of a Unity will reward you with Unity accolades in addition to sparks of eminence.
        THESE_ACCOLADES_NOT_ONLY_SERVE_AS_A_SYMBOL                                    = 17066,  -- These accolades not only serve as a symbol of prestige, but can also be exchanged for a variety of services.
        SOME_OF_THESE_SERVICES_INCLUDE_PURCHASING_ITEMS_SECURING                      = 17067,  -- Some of these services include purchasing items, securing battle zones for hunting Wanted targets, fees for strengthening equipment, and more.
        PLEASE_NOTE_THAT_YOU_MAY_ONLY_EXCHANGE_A                                      = 17068,  -- Please note that you may only exchange a maximum of # accolades per week (Earth time).
        YOU_MAY_SWITCH_UNITIES_ONCE_DURING_THE_UNITY                                  = 17069,  -- You may switch Unities once during the Unity ranking tabulation period.
        THIS_IS_NOT_A_DECISION_TO_BE_TAKEN                                            = 17070,  -- This is not a decision to be taken lightly, for switching Unities will cause you to forfeit any benefits you were receiving from your previous one.
        THIS_PROCESS_REQUIRES_A_FAIR_DEAL_OF_PAPERWORK                                = 17071,  -- This process requires a fair deal of paperwork, and the A.M.A.N. will charge you an accolade fee based on your rank.
        HOWEVER_YOUR_VALOROUS_DEEDS_REMAIN_WHEREVER_YOU_CHOOSE                        = 17072,  -- However, your valorous deeds remain wherever you choose to go, and you will not lose any other accolades.
        RANKINGS_ARE_DECIDED_THROUGH_THE_COMBINED_EFFORTS_OF                          = 17073,  -- Rankings are decided through the combined efforts of each of the Unity's members.
        THE_A_M_A_N_TABULATES_ALL_THE                                                 = 17074,  -- The A.M.A.N. tabulates all the good deeds done during a period of time and confers benefits on a Unity for the following ranking period.
        SOME_OF_THESE_BENEFITS_INCLUDE_CHANGES_TO_UNITY                               = 17075,  -- Some of these benefits include changes to Unity accolades gained and the effects of equipment earned from Wanted battles.
        YES_YOU_READ_THAT_CORRECTLY_THE_ATTRIBUTES_OF                                 = 17076,  -- Yes, you read that correctly--the attributes of certain equipment will increase in line with your Unity's ranking.
        ON_THE_OTHER_HAND_MEMBERS_OF_A_UNITY                                          = 17077,  -- On the other hand, members of a Unity that finds itself on the lower rungs will enjoy an increase in accolades and capacity points earned to help bring them up to par.
        ADDITIONALLY_AN_INDIVIDUAL_S_EVALUATION_IS_THE_SUM                            = 17078,  -- Additionally, an individual's evaluation is the sum of the accolades they have earned divided by #. A Unity's ranking is the average of all eligible members' individual evaluations.
        THE_A_M_A_N_DOES_NOT_LOOK                                                     = 17079,  -- The A.M.A.N. does not look kindly on those who only seek to siphon rewards from others' hard work, and thus only confers these boons on those who have collected at least a certain number of accolades.
        UNITY_LEADERS_MAY_ALSO_JOIN_YOU_AS_ALTER                                      = 17080,  -- Unity leaders may also join you as alter egos for a limited period of time.
        THOSE_WITH_EVALUATIONS_OF_OR_GREATER_WILL_BE                                  = 17081,  -- Those with evaluations of # or greater will be able to call forth an alter ego of their leader to assist them in battle.
        THOSE_ELIGIBLE_WILL_BE_ABLE_TO_USE_THE                                        = 17082,  -- Those eligible will be able to use the alter ego from the moment they acquire the appropriate ranking level until the tabulation after the next.
        A_LEADER_S_ALTER_EGO_GROWS_IN_POWER                                           = 17083,  -- A leader's alter ego grows in power the higher their Unity is ranked.
        CHANGING_UNITIES_WILL_REMOVE_THE_PLAYER_S_ABILITY                             = 17084,  -- Changing Unities will remove the player's ability to call forth their leader's alter ego at the moment they leave their current Unity, regardless of personal evaluation or remaining time.
        A_PLAYER_WILL_HAVE_TO_WORK_HARD_IN                                            = 17085,  -- A player will have to work hard in their new Unity and acquire a sufficient evaluation to regain the ability to call forth their new Unity's leader.
        IT_GOES_WITHOUT_SAYING_THAT_PLAYERS_MUST_FIRST                                = 17086,  -- It goes without saying that players must first have acquired a Trust permit in order to avail themselves of this opportunity.
        THOSE_DESIRING_TO_PARTICIPATE_SHOULD_SEEK_OUT_ONE                             = 17087,  -- Those desiring to participate should seek out one of the initiative's representatives, dressed in green, in one of the three nations.
        YOU_ARE_CURRENTLY_UNDER_UNITY_RESTRICTION_PLEASE_TRY                          = 17088,  -- You are currently under Unity restriction. Please try again during the next tabulation period.
        THE_A_M_A_N_HAS_REMOVED_THE                                                   = 17089,  -- The A.M.A.N. has removed the Unity restrictions placed on you. Please choose your Unity.
        YOU_CALL_OUT_FOR_AID_FROM_THE_UNITY                                           = 17090,  -- You call out for aid from the Unity leaders, but none have heeded your call. Please try again.
        YOU_HAVE_ALREADY_CHANGED_UNITIES_PLEASE_WAIT_UNTIL                            = 17091,  -- You have already changed Unities. Please wait until the next tabulation period.
        SHOULD_YOU_CHOOSE_TO_BE_TELEPORTED_TO_THIS                                    = 17092,  -- Should you choose to be teleported to this area, you will not have enough accolades to participate in the Wanted battle. Teleport anyway?
        TELEPORT_ANYWAY_YES_PLEASE_NO_THANK_YOU                                       = 17093,  -- Teleport anyway? Yes, please. No, thank you.
