        EACH_ACCENT_YOU_ADD_TO_YOUR_COSTUME_AFFECTS                                   = 17156,  -- Each accent you add to your costume affects the overall look, and he will determine a numerical value based upon the stuff you strut.
        YET_I_MUST_WARN_YOU_THAT_HE_HAS                                               = 17157,  -- Yet I must warn you that he has trained hard under Brygid's watchful eye, and recognizes that the trends of the season are as fickle as the westerly winds.
        IN_OTHER_WORDS_JUST_BECAUSE_YOU_HAVE_RECEIVED                                 = 17158,  -- In other words, just because you have received a particular score for wearing a given outfit, you are not guaranteed the same reception if you come back later donning the same garb.
        AND_OF_COURSE_THE_SWEETS_YOU_GIVE_ME                                          = 17159,  -- And of course, the sweets you give me plays an integral... Ahem! Forget I said anything!
