        MASTER_THE_ORB                                                                = 17252,  -- Master--the orb.
        YOU_HAVE_SET_HISTORY_ON_ITS_PROPER_COURSE                                     = 17253,  -- You have set history on its proper course yet again, having passed through the fourth gate that stood before you.
        YET_SELH_TEUS_S_WORDS_RING_TRUE_THE                                           = 17254,  -- Yet Selh'teus's words ring true--the darkness slumbering within you is great.
        HE_CLAIMS_THAT_NOT_EVEN_THE_CRYSTAL_IS                                        = 17255,  -- He claims that not even the crystal is enough to illuminate it.
        I_MUST_CONFESS_MY_TREPIDATION_AT_THE_CURRENT                                  = 17256,  -- I must confess my trepidation at the current state of affairs. What if the darkness overcomes you not in the future, but even earlier than I had anticipated?
        WHAT_A_MORBID_STATE_OF_AFFAIRS_WE_FIND                                        = 17257,  -- What a morbid state of affairs we find ourselves in.
        WE_MUST_TAKE_SOLACE_IN_THE_HOPE_THAT                                          = 17258,  -- We must take solace in the hope that the orb will guide you to safety, so that you will be prepared for the Reckoning.
