        IT_IS_NOT_UNHEARD_OF_FOR_POWER_HUNGRY                                         = 17550,  -- It is not unheard of for power-hungry sorcerers to trample over anyone who would stand in the way of their quest to become ever stronger-wonger.
        BUT_GARAZU_HOREIZU_WAS_A_FIEND_AMONG_FIENDS                                   = 17551,  -- But Garazu-Horeizu was a fiend among fiends. He employed powerful hypnosis magic, also known as the maelstrom--hence his moniker-woniker.
        GARAZU_HOREIZU_WAS_BRAZEN_IN_HIS_LUSTARU_FOR                                  = 17552,  -- Garazu-Horeizu was brazen in his lustaru for power.
