        YAGUDO_KEEP_ALL_THIER_MOST_PRIZED_POSSESSIONS_DEEP                            = 17569,  -- Yagudo keep all thier most prized possessions deep within a vault in Giddeus. You may be able-wable to lay claim to your quarry there, if you hurry.
        WE_CANNOT_WAIT_FOR_THE_FIVE_MINISTRIES_TO                                     = 17570,  -- We cannot wait for the five ministries to convene and make an official decision. Please make haste--and do be discreet about it.
