        I_SEE_SO_YOUR_OPERATION_IN_GIDDEUS_DIDN                                       = 17573,  -- I see. So your operation in Giddeus didn't quite go to plan.
        MY_NEXTARU_STEP_IS_TO_FIGURE_OUT_HOW                                          = 17574,  -- My nextaru step is to figure out how to break the news to the other ministers in Heavens Tower.
