        THE_VENGEFUL_SPIRIT_OF_GAREZU_HOREIZU_CAN_BE                                  = 17583,  -- ...the vengeful spirit of Garezu-Horeizu can be summoned back from Death's dark hall.
        COULD_HONOI_GOMOI_BE_AWARE_OF_THE_LEGENDS                                     = 17584,  -- Could Honoi-Gomoi be aware of the legends of the dolls?
        NO_THERE_IS_NO_WAY_HE_COULD_EVEN                                              = 17585,  -- No. There is no way he could... Even if he did, would he know the Manustery rites to...
        ACCORDING_TO_THE_TALE_THE_SPIRITARU_OF_GAREZU                                 = 17586,  -- According to the tale, the spiritaru of Garezu-Horeizu can be summoned back from Death's dark hall.
        BUT_IT_WOULD_TAKE_A_MAGE_OF_NEAR                                              = 17587,  -- But it would take a mage of near-unfathomable power to complete the incantation.
        AND_FOR_ALL_HIS_BLUSTER_HONOI_GOMOI_IS                                        = 17588,  -- And for all his bluster, Honoi-Gomoi is just a layman. He would be unable to do anything by himself.
        HRM_HRMMMMMM                                                                  = 17589,  -- Hrm. Hrmmmmmm!
        ALTHOUGH_WE_HAVE_NOT_YET_GOTTEN_THE_CURSED                                    = 17590,  -- Although we have not yet gotten the cursed trinketaru back, I must commend you on having unraveled part of this infernal tapestry. Here's a token of my appreciation--and please forget everything we discussed today.
        INCLUDING_ABOUT_THAT_EGG_BUSINESS_WUSINESS_NOT_THAT                           = 17591,  -- Including about that egg business-wusiness. Not that I could help you even if i wanted to.
