        SOMETHING_ABOUTARU_IT_SEEMS_FAMILIAR_YES_I_CAN                                = 17593,  -- Something aboutaru it seems familiar. Yes, I can picture a small Tarutaru playing like it was only yesterday...
        AH_ADVENTURER_I_THINK_I_KNOW_THE_CHILDREN                                     = 17594,  -- Ah, adventurer! I think I know the children who were playing with the doll. Could you bring it to them?
        DELIVER_THE_DOLL_SURE_NO_THANKS                                               = 17595,  -- Deliver the doll? Sure. No thanks.
        THOSE_CHILDREN_ARE_ALWAYS_SPOTTED_NEAR_A_WAREHOUSE                            = 17596,  -- Those children are always spotted near a warehouse by the wharf.
        I_DON_T_THINK_YOU_LL_RECEIVE_WEIVE                                            = 17597,  -- I don't think you'll receive-weive any compensation, but kindness is its own reward.
        THIS_PLACE_IS_A_LIBRARY_OFFICIALLY_KNOWN_AS                                   = 17598,  -- This place is a library, officially known as the Federal Book Repository for Magical Knowledge and Research and Book Repository of General Knowledges.
        WE_HAVE_NO_USE_HERE_FOR_SMELLY_OBNOXIOUS                                      = 17599,  -- We have no use here for smelly, obnoxious-woxious children's toys.
        HRM_PLEASE_DON_T_GO_AROUND_TELLING_EVERYONE                                   = 17600,  -- Hrm.... Please don't go around telling everyone about something being stolen from the Doll Chamber.
        I_SHALL_LEAVE_YOU_HERE_FOR_PREPARATIONS_TO                                    = 17601,  -- I shall leave you here, for preparations to meet with the other ministers must be made.
        BRING_THAT_TO_THE_WAREHOUSE_NEAR_THE_WATERFRONT                               = 17602,  -- Bring that % to the warehouse near the waterfront.
        HRMMMMMM_I_MUST_PREPARE_TO_MEET_WITH_THE                                      = 17603,  -- Hrmmmmmm... I must prepare to meet with the other ministers in Heavens Tower.
        HRM_PLEASE_DON_T_GO_AROUND_TELLING_EVERYONE_2                                 = 17604,  -- Hrm.... Please don't go around telling everyone about something being stolen from the doll chamber.
        I_MUST_PREPARE_TO_MEET_WITH_THE_OTHER                                         = 17605,  -- I must prepare to meet with the other ministers in Heavens Tower.
        OOOF_I_THINK_I_PULLED_MY_KNEE                                                 = 17606,  -- Ooof...I think I pulled my knee.
        Y_YOU_WHAT_RE_YOU_DOING_HERE                                                  = 17607,  -- Y-you! What're you doing here?
        HMPH_YOU_WON_T_GET_A_WORD_OUT                                                 = 17608,  -- Hmph! You won't get a word out of me, so don't even bother trying!
        THIS_IS_AN_EXPLANATION_OF_THE_ASSIST_CHANNEL                                  = 17609,  -- This is an explanation of the Assist Channel feature, which allows new and returning players to seek help from veteran adventurers.
        YOU_MUST_TAKE_ON_THE_RECORDS_OF_EMINENCE                                      = 17610,  -- You must take on the % Records of Eminence objective before receiving the explanation.
        YOU_MUST_COMPLETE_BEFORE_TAKING_ON_THE_RECORDS                                = 17611,  -- You must complete % before taking on the % Records of Eminence objective.
        WHAT_DO_YOU_WANT_TO_LEARN_ABOUT_WHAT                                          = 17612,  -- What do you want to learn about? What is the Assist Channel? How can I post a message? What are the requirements? Where can I access it? Tell me about mentor messages. Where can I find mentors? What are Thumbs Up and Warnings? What happens if I am muted? When do my posting rights expire? Nothing for now.
        THE_ASSIST_CHANNEL_IS_A_SPECIAL_CHAT_CHANNEL                                  = 17613,  -- The Assist Channel is a special chat channel that allows adventurers to ask questions and receive advice from veteran players known as mentors.
        PRESS_THE_SPACE_BAR_TO_BRING_UP_THE                                           = 17614,  -- Press the space bar to bring up the text window at the bottom of the screen and type /assistj (your message) or /assiste (your message) to post your message.
        YOU_CAN_ALSO_USE_AJ_FOR_ASSISTJ_AND                                           = 17615,  -- You can also use /aj for /assistj, and /ae for /assiste.
        ADDITIONALLY_PRESSING_CTRL_Q_WILL_DISPLAY_ASSISTJ_OR                          = 17616,  -- Additionally, pressing CTRL+Q will display /assistj or /assiste in the text window for you.
        YOU_CAN_CHANGE_THE_CTRL_Q_SHORTCUT_COMMAND                                    = 17617,  -- You can change the CTRL+Q shortcut command...
        BY_GOING_TO_MAIN_MENU_CONFIG_MISC_2                                           = 17618,  -- ...by going to Main Menu > Config > Misc. 2 > Key Assignment > Commands > Chat: /AssistE or /AssistJ.
        IT_IS_RECOMMENDED_THAT_YOU_USE_ASSISTJ_AJ                                     = 17619,  -- It is recommended that you use /assistj (/aj) when posting in Japanese, and /assiste (/ae) when posting in English.
        YOU_MUST_MEET_ONE_OF_THE_FOLLOWING_CONDITIONS                                 = 17620,  -- You must meet one of the following conditions in order to post to the Assist Channel.
        ID_1_YOU_ARE_A_NEW_PLAYER_YOU_MAY                                             = 17621,  -- 1. You are a new player You may post messages from the moment you first set foot in Vana'diel.
        ID_2_YOU_ARE_A_RETURNEE_AS_A_RETURNING                                        = 17622,  -- 2. You are a returnee As a returning player, you may post messages upon logging in with a character that has not logged in for at least 48 days.
        ID_3_YOU_ARE_A_MENTOR_YOU_MAY_POST                                            = 17623,  -- 3. You are a mentor You may post messages as long as you remain a mentor to other players.
        NEW_PLAYERS_AND_RETURNEES_MAY_POST_MESSAGES_UNTIL                             = 17624,  -- New players and returnees may post messages until they have been logged in for a total of 48 hours since first receiving their posting rights.
        IF_YOU_WISH_TO_CHECK_HOW_LONG_YOU                                             = 17625,  -- If you wish to check how long you can continue to post for, speak to an and choose "When do my posting rights expire?" to see how much time you have left.
        THE_ASSIST_CHANNEL_CAN_ONLY_BE_USED_IN                                        = 17626,  -- The Assist Channel can only be used in the following areas.
        AVAILABLE_AREAS                                                               = 17627,  -- Available areas: %, %, %, %, %, %...
        ID_17628                                                                      = 17628,  -- ...%, %, %, %, %, %, %, %...
        ID_17629                                                                      = 17629,  -- ...%, %, %, %, %, %, %, %...
        AND_YOUR_MOG_HOUSE_RENT_A_ROOM                                                = 17630,  -- ...%, %, %, and your Mog House (Rent-a-Room).
        YOU_CANNOT_POST_OR_READ_MESSAGES_OUTSIDE_OF                                   = 17631,  -- You cannot post or read messages outside of the areas listed above.
        EVEN_IN_AREAS_WHERE_MESSAGES_ARE_ALLOWED_YOU                                  = 17632,  -- Even in areas where messages are allowed, you cannot post consecutive messages. Please wait a while after posting a message.
        MENTOR_MESSAGES_ARE_ACCOMPANIED_BY_A_FLAG_O                                   = 17633,  -- Mentor messages are accompanied by a flag (o/) marker. This marker indicates the mentor's reliability (Mentor Class) and experience as an adventurer (Mastery Rank).
        AS_A_MENTOR_S_MENTOR_CLASS_INCREASES_THE                                      = 17634,  -- As a mentor's Mentor Class increases, the color and shape of the marker will change: o/ > o9 > oC
        A_OC_MARKER_IS_A_SIGN_THAT_THE                                                = 17635,  -- A oC marker is a sign that the mentor has earned the highest levels of trust from other adventurers.
        THE_NUMBER_AFFIXED_TO_THE_MARKER_IS_THE                                       = 17636,  -- The number affixed to the marker is the mentor's Mastery Rank, and indicates how experienced the mentor is as an adventurer.
        THE_HIGHER_THE_NUMBER_THE_MORE_EXPERIENCED_THE                                = 17637,  -- The higher the number, the more experienced the mentor is.
        YOU_CAN_CHECK_YOUR_OWN_MASTERY_RANK_EVEN                                      = 17638,  -- You can check your own Mastery Rank even if you do not serve as a mentor, so feel free to take a look every now and then if you are curious.
        YOU_CAN_CHECK_YOUR_MASTERY_RANK_BY_GOING                                      = 17639,  -- You can check your Mastery Rank by going to Main Menu > Status > Profile.
        IF_YOU_WISH_TO_SPEAK_DIRECTLY_TO_A                                            = 17640,  -- If you wish to speak directly to a mentor, you can search for mentors by going to Main Menu > Help Desk > Mentor Search.
        THE_THUMBS_UP_FEATURE_ENABLES_YOU_TO_LET                                      = 17641,  -- The Thumbs Up feature enables you to let mentors know when their comments proved to be especially helpful.
        MENTORS_WHO_EARN_LOTS_OF_THUMBS_UP_REPLIES                                    = 17642,  -- Mentors who earn lots of Thumbs Up replies from other adventurers will see their Mentor Class increase.
        REMEMBER_TO_GIVE_A_THUMBS_UP_TO_ANY                                           = 17643,  -- Remember to give a Thumbs Up to any mentor you feel helped you out or taught you something useful.
        A_WARNING_IS_A_FEATURE_THAT_CAN_ONLY                                          = 17644,  -- A Warning is a feature that can only be used by mentors.
        PLEASE_USE_THIS_FEATURE_WHEN_A_POST_S                                         = 17645,  -- Please use this feature when a post's contents are insufficient or otherwise may be construed as harassment.
        TO_SEND_A_THUMBS_UP_OR_WARNING_TO                                             = 17646,  -- To send a Thumbs Up or Warning to another player, open the Chat Log Window and move the cursor over the relevant message and press the confirm button (Enter key) to bring up the evaluation menu.
        EVALUATIONS_CAN_BE_MADE_FOR_10_MINUTES_FOLLOWING                              = 17647,  -- Evaluations can be made for 10 minutes following the designated player's latest post to the Assist Channel.
        YOU_MAY_SEND_UP_TO_ONE_THUMBS_UP                                              = 17648,  -- You may send up to one Thumbs Up and one Warning per day (Earth time).
        THE_MUTE_FEATURE_PLACES_RESTRICTIONS_ON_YOUR_ABILITY                          = 17649,  -- The Mute feature places restrictions on your ability to post, meaning that other players will be unable to see the messages you post to the Assist Channel.
        PLEASE_REFRAIN_FROM_POSTING_UNSUITABLE_CONTENT_SO_THAT                        = 17650,  -- Please refrain from posting unsuitable content so that the veteran adventurers are not forced to mute you.
        MUTE_STATUS_CAN_BE_REMOVED_BY_PLAYERS_THAT                                    = 17651,  -- Mute status can be removed by players that have the necessary Mute List access rights, or it will be removed automatically 24 hours (Earth time) after the mute status was enabled.
        YOU_ARE_FREE_TO_POST_MESSAGES_TO_THE                                          = 17652,  -- You are free to post messages to the Assist Channel until you decide to stop serving as a mentor.
        YOU_MAY_POST_MESSAGES_TO_THE_ASSIST_CHANNEL                                   = 17653,  -- You may post messages to the Assist Channel until : on //. (Time remaining: Approx. # [sec./min./hr.])
